INSERT INTO public."Epic" VALUES ('cmn14a8d0083g4co7al6zw241', 'EP-DEPLOY-001', 'Standalone Docker Deployment with Managed Ollama', 'Single docker compose up brings portal + Postgres + Ollama online. Platform UI manages Docker/Ollama directly with auto-detection of host GPU/RAM and zero-config model selection.', 'open', '2026-03-22 02:07:45.876', '2026-03-22 20:37:36.957', NULL, NULL, '2026-03-22 05:03:10.03', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8di083n4co7hu6es2pm', 'EP-AGENT-EXEC-001', 'Agent Task Execution with HITL Governance', 'Agents propose real actions (create backlog items, modify products, update EA). Humans approve before execution. Audit-logged via AuthorizationDecisionLog for regulated industry compliance.', 'open', '2026-03-22 02:07:45.894', '2026-03-22 20:37:36.971', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('e33c71ed-e404-45ec-874d-22325b130383', 'EP-03f6a529-9bfa-4095-a484-3a232d0a0608', 'EA Modeler', 'Graph-native enterprise architecture modelling canvas built on JointJS + ArchiMate 4. Neo4j owns the semantic model. Scenarios capture proposed future states. Snapshots are immutable approval artefacts. Whiteboard-first interaction model with drag-to-connect and direct manipulation.
INSERT INTO public."Epic" VALUES ('6cccc0c9-de96-4d29-aa91-77708e109266', 'EP-16fed341-87a2-4cf1-84ca-d4c4bc7b74ba', 'Calendaring Core', 'Central scheduling and calendar kernel for the platform. PostgreSQL is the canonical authority — Google Calendar and Microsoft Outlook/Exchange are projection adapters, never the source of truth. Covers four subdomains: (1) platform job scheduling for AI agents and procedural automation; (2) calendar and availability for employees (business calendars, availability windows, holidays); (3) workforce shift planning (shift templates, instances, time-off); (4) appointment and dispatch for customer-facing bookings. ICS/RFC-5545 export enables provider-agnostic customer invites. External calendar push sync is included as an optional per-user opt-in. Shift optimisation (OR-Tools) and field dispatch are follow-on epics.
INSERT INTO public."Epic" VALUES ('8f72211f-6fd9-46c8-bbb3-126fc1a76dc2', 'EP-2819efcf-11ba-4549-97e7-e59d8fd31048', 'Miro Board Collaboration', 'Integrate Miro as a collaboration surface for EA models and planning artifacts. Platform EA views (value streams, capability maps, ArchiMate diagrams) can be published to Miro boards for stakeholder review and workshop facilitation. Changes made in Miro sync back via webhooks. OAuth 2.0 team-level auth. Enables non-platform users (executives, external consultants) to participate in architecture decisions without needing platform accounts.', 'open', '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('b431bb8d-1587-4ac1-a92f-2b982f313bcf', 'EP-CODEGEN-001', 'Build Studio Code Generation Tools', 'MCP tools for sandbox code generation: generate schema, UI components, API routes. Testing + verification tools: run tests, type-check, lint. The backend muscle for the Build Studio.', 'open', '2026-03-15 15:41:32.837', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('d9e53b39-b42d-4e12-a4b8-a6ea2f1f3e91', 'EP-DEDUP-001', 'Duplicate Detection + Cross-Team Collaboration', 'When a user proposes a new feature or product, the platform checks existing builds, backlog items, epics, and registered third-party products across the entire enterprise for overlap. Connects users working on similar initiatives. Suggests reuse of existing products or containers. Prevents organizational duplication at scale. Depends on portfolio taxonomy, product inventory, and EA model being populated.', 'open', '2026-03-15 15:49:54.119', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('fc26c154-89a0-4f99-b592-7427c6305ead', 'EP-DEPLOY-002', 'Build Studio Deployment Pipeline', 'Apply sandbox changes to running platform: migrations, code deployment, rollback. Audit trail for every deployment action. Regulated-industry compliance controls.', 'open', '2026-03-15 15:41:32.841', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('73c25326-1e2f-4606-8e73-e6e1a2b3a0b6', 'EP-DISCOVERY-001', 'Bootstrap Infrastructure Discovery and Portfolio Quality Foundation', 'Track the local bootstrap discovery pipeline, normalized inventory, graph projection, foundational attribution, and quality issue surfacing.', 'in-progress', '2026-03-14 06:33:59.06', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('6334d4f7-76ac-4ea1-9918-9d43c4529d90', 'EP-EA-DP', 'Digital Product as EA First-Class Citizen', 'Extend EA modeling layer with Digital Product as a cross-layer element type in a new product domain. Bridge conceptual EA views to operational reality via health overlay and drill-through navigation. New viewpoints: Product Landscape (all products across portfolios), Product Dependency (single product dependencies), Change Impact (RFC overlay on product landscape). Standards-aware ArchiMate interchange with stereotype annotation.', 'open', '2026-03-21 18:54:17.624', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('f0b39253-8cc4-4218-add1-d293ed1fce1e', 'EP-EA-MODEL-001', 'Enterprise Architecture Modeling Foundation and Canvas', 'Restore the EA metamodel, views, canvas, relationship handling, and structured notation groundwork added for the EA workspace.', 'in-progress', '2026-03-14 06:33:59.039', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('6969c130-422a-424c-8ed9-714932b93539', 'EP-3e61e510-8b65-4878-ab59-c286a3283777', 'GDPR Governance Entity', 'Register GDPR (EU 2016/679) as a first-class regulation in the EP-GRC-001 compliance engine. Populates obligations from key GDPR articles, adds processing activity records (Art 30), Data Protection Impact Assessments (Art 35), Data Subject Request workflows (Arts 15-22), breach notification pipeline (Art 33/34), consent management per product/service, and cross-border transfer tracking (Chapter V — SCCs, adequacy decisions, BCRs). DPO assignment is tracked via EmployeeProfile. All GDPR obligations link to the existing control, evidence, and audit infrastructure.', 'open', '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('c0615741-bb92-4233-a2ed-7f978a66ca06', 'EP-5328a6f9-fe50-486d-bc8a-14ac76480c10', 'Unified Work Item Types (Phase 6B)', 'Extend the backlog system with a workItemType discriminator (story, bug, enabler, improvement, demand, incident, problem, change-request) and ITSM traceability fields (originType, originId). Enables the D2C-to-R2D traceability chain: incident → problem → bug → story.', 'open', '2026-03-21 00:34:52.23', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('7bff2865-75c5-41e8-b748-f41409c68036', 'EP-5a72c7de-0ec0-4d0e-a51b-8073a3feccf8', 'Financial Management Suite', 'End-to-end financial management capability for business operators. Covers invoicing (create, send, track, collect), accounts payable (supplier management, bills, purchase orders, payment runs), banking and reconciliation (bank feeds, matching, cash position), recurring billing and credit control (subscriptions, dunning, aging), expense management (employee claims, receipts, approvals, reimbursement), financial reporting (P&L, balance sheet, aged debtors/creditors, cash flow, budgets), fixed asset management (register, depreciation, disposal), and archetype-driven financial setup (chart of accounts, tax codes, payment terms, invoice templates seeded from storefront business type). DPF is the experience layer; ERPNext remains the ledger of record per Finance Hub Architecture spec.', 'in-progress', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('1a5f5be1-fe4e-4e60-9c1c-754eeb67fc9b', 'EP-65af8b00-0ded-428a-9955-a4b289b6957c', 'Build Studio UX Streamlining & Standards Integration', 'Wire UX evaluation into the AI coworker (axe-core + Playwright page analysis), integrate platform usability standards into the Build Studio pipeline (coding agent prompts, review checklists, Playwright assertions, phase gates), and automate the evidence chain for non-developer users. Dev toggle gates technical depth. Non-devs describe intent in plain language, agent produces all regulatory artifacts autonomously.', 'open', '2026-03-21 03:34:36.1', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('25cde4e7-c582-4e55-a71e-ac6460897ed1', 'EP-6ba1a394-4d25-40fd-8127-c5939a483234', 'HR Core', 'Native employee relationship management built directly on the existing Prisma schema — no external HRIS database. Adds EmployeeProfile extending User with a full lifecycle state machine (prospect → onboarding → active → on_leave → suspended → offboarded), domain attribution via TaxonomyNode, and an HR workspace with list, search, and detail pages. Platform role assignment actions (UserGroup management) are included. Everything stays in one PostgreSQL database. Customer portal and payroll integrations are separate epics.
INSERT INTO public."Epic" VALUES ('f232950d-70f9-4fc9-874f-1de96aca8d75', 'EP-75eef2cb-943b-4360-8dd1-727f69aff992', 'Regulation & Standards Onboarding', 'Generic onboarding process for any regulation, standard, or framework. 4-step wizard, AI coworker entry point, sourceType extension, policy-obligation many-to-many, and critical UI enhancements.', 'open', '2026-03-21 15:07:56.578', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('37f38130-ed84-4093-9a8d-b235f02f5a1b', 'EP-7a906c92-5b05-4873-be85-02778aba4c31', 'Infrastructure Registry', 'Operational footprint registry: track Docker instances, databases, services, and their provider/consumer relationships across portfolios. Links the foundational infrastructure to the manufacturing domain. Enables dependency impact analysis and operational visibility.
INSERT INTO public."Epic" VALUES ('2e14ccb5-d68b-4ca6-8725-d1479a587739', 'EP-8a7d45de-a82c-48f4-a3f8-3c4cac79eba3', 'Financial Management — Deferred Decision Review', 'Review gate for features deliberately excluded from EP-FINMGMT-001 based on public discourse analysis (2026-03-20). Each item represents a deferred capability with a specific demand signal that should trigger re-evaluation. Do not action these items speculatively — only open when the triggering condition is observed from real customer usage.', 'open', '2026-03-21 00:35:08.205', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('22e501fe-11e1-413b-a554-ea2fb13e9d62', 'EP-ADMIN-001', 'Feature Toggle — Enable/Disable Platform Capabilities', 'Admin-level enable/disable toggles for major platform features (Storefront, Compliance, Finance, Build Studio, EA Modeler, etc.). Not every business needs every feature — disabled features hide from navigation, workspace tiles, and agent routing. Reduces complexity for users who only need a subset of the platform. Should be configurable during onboarding and from Admin > Settings.', 'open', '2026-03-21 21:06:28.927', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('03f1d67e-27e6-4d71-86b9-e3377e251ee9', 'EP-AI-COWORKER-001', 'AI Agent Co-worker UX', 'Track the route-aware AI co-worker panel, agent routing, messaging, and contextual teammate UX integrated into the portal shell.', 'done', '2026-03-14 06:33:59.052', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('f11c1089-4179-4a68-8979-d3199f226d52', 'EP-AI-PROVIDERS-001', 'AI Provider Registry, Expanded Providers, and Local AI OOTB', 'Restore the AI provider registry, expanded provider support, model discovery and profiling, and Docker/Ollama out-of-the-box workstream.', 'done', '2026-03-14 06:33:59.048', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('ee20b6dc-239c-4348-8dc9-b19dda24445b', 'EP-AUTONOMY-001', 'Agent Autonomy Controls', 'UX dial for human involvement level per build. Ranges from full HITL (approve every action) to full autonomy (spend limits only). Ties into ADP governance levels from EP-WORKFORCE-001.', 'open', '2026-03-15 15:41:32.833', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('dd4d13ea-6f76-483f-87be-1112adee8bc0', 'EP-BACKLOG-FOUND-001', 'Backlog and Epic Management Foundation', 'Restore the foundational backlog system and epic grouping capability that was introduced to manage work across the digital product factory.', 'done', '2026-03-14 06:33:59.031', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('ce048194-9a2a-4b7e-97ae-6a43ca26546b', 'EP-BUILD-A69429', 'Student Payment & Registration Flow v1.0.0', NULL, 'open', '2026-03-15 06:38:07.519', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('8587a2ef-e084-48d0-9370-4dd853c8a58f', 'EP-CAL-001', 'Calendar Infrastructure — Unified Scheduling & Event System', 'A calendar event framework serving as platform scheduling infrastructure. Subsumes ScheduledJob into a unified CalendarEvent model supporting one-time and recurring events, automated action execution with backlog-based audit trails, role-contextual UX surfaces, and MCP tool exposure for AI coworkers.', 'in-progress', '2026-03-15 22:47:41.87', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('d0735538-868a-433b-ba5a-83557786a9c5', 'EP-CHG-MGMT', 'Change & Deployment Management', 'ITIL-style change management process covering platform changes and customer-managed external systems. RFC umbrella model above existing ChangePromotion, with business-aware deployment windows derived from operating hours and storefront traffic. Impact analysis integration with operational graph. Maintenance window enforcement via calendar, booking blocks, and status banners. Standard change catalog for pre-approved routine operations.', 'open', '2026-03-21 18:54:17.59', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('e9b83861-6d4f-4032-b06d-3e332ab2920f', 'EP-EA-REF-001', 'EA Reference Model Assessment and Reference Architecture Loading', 'Track the IT4IT-based reference model assessment foundation and the repeatable reference architecture loading path needed to create live EA models and views from repo-backed artifacts.', 'in-progress', '2026-03-14 06:33:59.044', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('5703af92-74df-4445-ae31-e56f1437e847', 'EP-EMP-WS-001', 'Employee Workspace Interaction Model', 'Make the default employee workspace the shared front door for all employees, with role-aware provider, consumer, and collaboration modes. Employees should use one portal shell while seeing different work, services, apps, and handoffs based on role and current responsibilities.
INSERT INTO public."Epic" VALUES ('7e6fdaf8-78db-44e8-a5be-beb0f766f060', 'EP-FINANCE-001', 'Financial Primitives and Budget Management', 'Implement robust finance operations in the platform with ERPNext as the execution engine (multi-business, multi-company), including accounts payable, accounts receivable, payroll, taxes, shopping cart to receivables workflow, and CRM handoff for trainer signup + billing events.
INSERT INTO public."Epic" VALUES ('730530db-de24-4f6a-83ec-abfe021004b2', 'EP-FOUND-OPS', 'Foundation Portfolio Operations Console', 'Operational interface for Foundation portfolio owners to manage underlying technology. Combines infrastructure dashboard, lightweight health probes (container, database, service, image), operational dependency graph with impact analysis, and probe history/trend analysis. Builds on existing InventoryEntity and InventoryRelationship models. Future-proofed for cloud and distributed deployment.', 'open', '2026-03-21 18:54:17.547', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('7dac5585-a78a-4d20-a798-7bdf787749a0', 'EP-FULL-OBS', 'Full Observability Integration', 'Future epic for deep observability beyond lightweight health probes. Docker stats API integration (real-time CPU/memory/network), database performance views (slow queries, lock contention, replication lag), application-level metrics (request rates, error rates, latency percentiles), custom dashboard builder, external notification channels (email, webhook, Slack), distributed tracing, and log aggregation. Triggers when operational complexity outgrows the health probe model from EP-FOUND-OPS.', 'open', '2026-03-21 18:54:17.663', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('4779dba1-8816-4a4a-87da-ac2dc1408108', 'EP-GOV-FOUND-001', 'Unified Identity, Access, and Agent Governance Foundation', 'Restore the shared human, team, delegation, and agent-governance foundation intended to support HR core, CRM, and governed AI execution.', 'in-progress', '2026-03-14 06:33:59.056', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('eb8ceefc-d525-447c-a12f-23e9e86d2072', 'EP-INF-003', 'Provider Model Registry', 'Adapter-based model card extraction for all providers. Metadata-driven dimension scores, pricing, capabilities, and model classification. Drift detection via rawMetadataHash. Backfill function for existing profiles.', 'done', '2026-03-21 01:12:06.744', '2026-03-22 02:35:28.707', NULL, NULL, '2026-03-21 01:12:06.673', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('a9ffe9be-06ff-402d-a1c5-d144e7b6115f', 'EP-INF-004', 'Rate Limits & Capacity Management', 'In-memory rate tracker with sliding-window token/request counting. Capacity pre-flight checks integrated into routing pipeline. Rate-limit response learning (429/Retry-After). Exponential backoff recovery scheduler.', 'done', '2026-03-21 01:12:06.77', '2026-03-22 02:35:28.707', NULL, NULL, '2026-03-21 01:12:06.769', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('31687e61-9db8-441e-ab6f-ee30d57f2eda', 'EP-INF-005a', 'Contract-Based Selection', 'RequestContract type capturing modality, tool requirements, token budgets, sensitivity, and quality posture. Deterministic inferContract() from raw request context. routeEndpointV2 pipeline with cost-per-success ranking replacing dimension scoring.', 'done', '2026-03-21 01:12:06.772', '2026-03-22 02:35:28.707', NULL, NULL, '2026-03-21 01:12:06.772', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('dc311b3f-13ac-4e38-b04d-03af813bcc39', 'EP-INF-005b', 'Execution Recipes', 'ExecutionRecipe DB model with provider-specific settings, tool policy, and response policy. Seed recipe builder deriving settings from model card + contract. Recipe loader with champion/challenger selection. RoutedExecutionPlan attached to RouteDecision.', 'done', '2026-03-21 01:12:06.774', '2026-03-22 02:35:28.707', NULL, NULL, '2026-03-21 01:12:06.773', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('d6ecc57a-7605-4c8a-b172-71045a19f9cd', 'EP-INF-006', 'Adaptive Loop & Evaluation Realignment', 'Reward signal computation from outcome signals (latency, token efficiency, tool accuracy, user satisfaction). Route outcome recording. Recipe performance tracking with EMA smoothing. Champion-challenger exploration with promotion/demotion. Golden test realignment trigger.', 'done', '2026-03-21 01:12:06.775', '2026-03-22 02:35:28.707', NULL, NULL, '2026-03-21 01:12:06.775', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('1c6deb63-d045-414b-b394-2a1b098d38cc', 'EP-INF-007', 'Routing Redesign Activation', 'Wire routeEndpointV2 into the live agent-coworker call site with legacy fallback. Seed execution recipes for all active model profiles. Backfill ModelCard fields. Create backlog entries for the full routing redesign initiative.', 'in-progress', '2026-03-21 01:12:06.778', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('9443f643-f6ff-4fb8-850a-b51908085de5', 'EP-INTAKE-001', 'Portfolio-Aware Feature Intake', 'Smart intake layer: when a user describes what they want, the agent searches existing portfolio/taxonomy/products for related items, suggests starting points, and decomposes large ideas into feature sets with backlog items.', 'open', '2026-03-15 15:41:32.822', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('4535e0f1-1c28-492f-aeff-20e9eaf32f10', 'EP-KERNEL-001', 'Trusted AI Kernel — Model Aptitude Assessment & Capability Badging', 'AI models profiled like people — aptitude assessments that reveal personality, strengths, and best-fit roles. Minimum capability badges to function in a role. Specialty recognition for purpose-trained models (Hugging Face ecosystem). Models must REFUSE tasks beyond their certified capabilities — say no, don''t hallucinate. Team composition logic assembles diverse model teams for complex tasks (Scott Page cognitive diversity framework). Ties to Trusted AI Kernel trust lifecycle (Learning→Practicing→Innate). Current state: naked models with no guardrails produce trial-and-error chaos — inflated eval scores, routing to incapable models, no explanation of why a model was chosen or what it can''t do.', 'open', '2026-03-21 19:46:48.881', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('ff4e242b-2343-434d-b8d6-21aef9b1f58b', 'EP-MCP-001', 'MCP Server Registry + Marketplace Integration', 'Visible MCP server configurations in AI Workforce UX. Browse/install tools from MCP marketplaces. Each agent shows which MCP tools it has access to. Admin can enable/disable/configure MCP servers per agent or globally. Future: community marketplace for sharing custom tools.', 'open', '2026-03-15 19:45:37.242', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('a1036590-798d-4518-a5b6-7997b0fb7c58', 'EP-MCP-ACT-001', 'MCP Catalog Activation & External Services Surface', 'Enable lifecycle for external MCP services: discover from catalog, activate with connection config, health check, tool discovery, admin surface. Spec: docs/superpowers/specs/2026-03-20-mcp-activation-and-services-surface-design.md', 'in-progress', '2026-03-20 23:28:01.35', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8h5084z4co7kjfg09km', 'EP-MOBILE-DYN-001', 'Mobile Dynamic Content Renderer', 'Schema-driven form and view rendering engine. Consumes definitions from /api/v1/dynamic/*.', 'open', '2026-03-22 02:07:46.025', '2026-03-22 20:37:37.065', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('63500ecb-148b-4c54-bc3f-dadaa5f99711', 'EP-OAUTH-001', 'Generic OAuth Authorization Code Flow for AI Providers', 'Add OAuth 2.0 authorization code + PKCE as a generic auth method for AI providers. Admin-initiated browser sign-in stores encrypted access + refresh tokens platform-wide. Data-driven: providers declare authorizeUrl, tokenUrl, oauthClientId in registry. OpenAI Codex is the first consumer (ChatGPT subscription access). Spec: docs/superpowers/specs/2026-03-21-provider-oauth-authorization-code-design.md', 'open', '2026-03-21 07:35:34.646', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('1ef5b644-14e1-47bf-a7b1-f252b7922ab7', 'EP-OAUTH-002', 'ChatGPT Backend Adapter — Subscription OAuth as Chat Provider', 'Build an execution adapter for the ChatGPT backend API (chatgpt.com/backend-api/) so subscription OAuth tokens can power chat completions in the AI co-worker. Auto-register a chat-capable route when Codex OAuth is configured. Fallback logic: if no other chat provider is active, use ChatGPT subscription. Depends on EP-OAUTH-001 (OAuth infrastructure, complete). Spec: docs/superpowers/specs/2026-03-21-chatgpt-backend-adapter-design.md', 'open', '2026-03-21 15:50:48.711', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('50935f93-c61d-4dcf-b745-db2075b1779e', 'EP-ONBOARD-001', 'COO-Led Platform Onboarding', 'AI Coworker-led setup experience where the COO persona guides non-technical users through initial platform configuration. Ollama auto-bootstraps on first launch. Spec: docs/superpowers/specs/2026-03-21-coo-led-onboarding-design.md', 'open', '2026-03-21 18:11:17.756', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('825d745e-e7f0-4540-b60a-23850157e469', 'EP-ONBOARD-002', 'Platform Extensibility Demo (Onboarding)', 'Guided walkthrough of Build Studio self-development during onboarding. Parked until the self-dev pipeline is production-ready.', 'open', '2026-03-21 18:11:17.777', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('ec3111a8-8d56-49f9-8158-6c062a6778ef', 'EP-ONTOLOGY', 'Digital Product Unified Ontology', 'Formal ontology specification unifying IT4IT value streams, CSDM entity relationships, ITIL v5 practices, and ArchiMate notation around Digital Product as the anchor entity. Includes AI agent identity model (workforce/operator/component aspects), standards gap register, cross-standard mapping tables, and evolution model. Living specification that evolves from implementation learnings and real-world deployments. Positions this platform as a reference implementation informing CSDM 6, ITIL v5 practice guides, and future ArchiMate extensions.', 'open', '2026-03-21 18:54:17.645', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('8fec3567-7d19-4ac6-bc59-f576bf2f410c', 'EP-PARALLEL-001', 'Parallel Feature Execution Engine', 'Multiple FeatureBuilds running concurrently with independent sandboxes, managed by an orchestrator agent. Investment controls (budget ceiling, autonomy level per build). The factory floor.', 'open', '2026-03-15 15:41:32.829', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('a5d637da-0ee5-4235-bdad-034f6dd9704a', 'EP-PARTNER-001', 'Partner Access — Third-Party Collaboration Model', 'Many organizations have partners that are neither customers nor employees — suppliers, distributors, consultants, agencies, affiliates. They need controlled platform access with different permissions, visibility, and data boundaries than customers or employees. Needs its own access model, portal experience, and role hierarchy.', 'open', '2026-03-21 21:09:43.974', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('88cd1f5c-16b9-41d2-90bc-6c7c87f403a6', 'EP-PORTAL-FOUND-001', 'Portal, Portfolio, Inventory, and Workspace Surface Foundation', 'Reestablish the core platform shell and major route surfaces created during the last four days: portfolio, inventory, employee, customer, ops, platform, admin, and supporting portfolio metrics.', 'done', '2026-03-14 06:33:59.02', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('714be36e-e362-417f-97aa-9208b6c0feb4', 'EP-PROCESS-001', 'Process Improvement AI Observer', 'A background AI coworker that observes human/agent dialog across all conversations. Identifies friction, repeated questions, failed tool calls, missed context, and UX gaps. Automatically creates backlog items in the correct product backlog with proper context. Core MVP capability for iterative platform improvement. Not a separate UI — runs silently and surfaces findings through the backlog system.', 'open', '2026-03-15 20:43:24.788', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('e9eafd32-cbe7-45eb-b71e-bb71e327ba4a', 'EP-QUALITY-001', 'Product Quality Feedback and Error Reporting', 'Capture runtime errors, user-reported issues, and page feedback. Route to the responsible digital product owner via the taxonomy. AI co-worker assists with error context and reporting. Every page has a feedback option.', 'open', '2026-03-14 21:51:35.756', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('19068647-8021-40ef-9bda-d9b02a98cb36', 'EP-REFACTOR-001', 'Platform Refactoring — Technical Debt Reduction', 'Ongoing refactoring to centralize duplicated patterns, reduce technical debt, and improve maintainability. 20% budget rule: when duplicate patterns are noticed during feature work, log them here.', 'open', '2026-03-15 15:08:33.929', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('5b8148bc-b44f-4845-b478-2d951c5b8e96', 'EP-SECRETARY-001', 'WhatsApp Secretary Gateway & Human Coordination', 'Company-facing WhatsApp secretary identity, employee channel binding, governed authority resolution, shared human ask queue, and proactive follow-up/reminder workflows.', 'open', '2026-03-21 17:19:52.429', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('96c85bfa-7542-48f2-b89c-c73397c59165', 'EP-SELF-DEV-001', 'AI-Driven Platform Self-Development', 'Enable the platform to write new functionality for non-developers. AI agents propose code changes, create components, and deploy updates through governed workflows with human approval. The platform iterates on itself within the 4 portfolio contexts.
INSERT INTO public."Epic" VALUES ('cmn14a8nq086l4co74qa03hzs', 'EP-STORE-001', 'Storefront Foundation', 'Public-facing storefront with archetype-driven CTA, unified sign-in, and shell admin. Spec: docs/superpowers/specs/2026-03-19-storefront-foundation-design.md', 'done', '2026-03-22 02:07:46.261', '2026-03-22 02:07:46.261', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('668312f1-dee5-40ce-ad12-bd2789eb1b08', 'EP-STORE-003', 'Storefront Booking Calendar — Availability, Slot Computation & Scheduling Patterns', 'Availability-first architecture with computed slots for booking-enabled storefronts. Three scheduling patterns (slot-based, class/capacity, recurring). ServiceProvider + ProviderAvailability + BookingHold. Archetype-driven defaults. Spec: docs/superpowers/specs/2026-03-20-storefront-booking-calendar-design.md', 'open', '2026-03-21 03:33:45.95', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8e3083u4co7t1ph5k8v', 'EP-REST-API-001', 'Platform REST API v1', 'Extract business logic from server actions into shared functions. Expose as versioned REST endpoints. JWT auth alongside existing session auth. OpenAPI spec generation.', 'open', '2026-03-22 02:07:45.915', '2026-03-22 20:37:36.988', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8ff084c4co7fngwt40p', 'EP-MOBILE-FOUND-001', 'Mobile Companion App Foundation', 'Expo project scaffold, auth flow, navigation shell, offline infrastructure, push notifications.', 'open', '2026-03-22 02:07:45.963', '2026-03-22 20:37:37.022', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8gb084n4co7m6ht7r0d', 'EP-MOBILE-FEAT-001', 'Mobile Companion App Features', 'Core feature screens with full offline caching and test coverage.', 'open', '2026-03-22 02:07:45.995', '2026-03-22 20:37:37.044', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('79324174-8132-4de8-980d-aa39a9c72f49', 'EP-UPLOAD-001', 'File Upload + Document Parsing for Build Studio', 'Upload spreadsheets, docs, emails, PDFs during feature intake. Agent parses documents to extract structure (columns, fields, processes). Files attached to FeatureBuilds and linked to backlog items. Airtable-style upload-to-data-model flow.', 'open', '2026-03-15 18:47:15.679', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('a9312e0e-f1c3-4326-8c4b-86617b88f5d2', 'EP-UX-PERSONA-001', 'AI Agent Personality Preferences — Per-User Tone & Style', 'Each user can set their preferred AI coworker personality within org-defined boundaries. Configured during initial user onboarding and adjustable in user settings. Options like formal/casual, concise/detailed, proactive/reactive. Organization admin sets guardrails (e.g., always professional, no humor) — user preferences work within those bounds. Applies across all agent interactions for that user. Corporate solution so personality stays appropriate but adapts to individual work style.', 'open', '2026-03-21 21:18:51.93', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('6701ef50-4d3c-440d-8bc8-d0e8b5954d49', 'EP-WORKFORCE-001', 'Unified Human + AI Workforce Management', 'Transform the Employee route into a full workforce view showing both human roles and AI agents as a single team. ADP autonomy levels, RACI-A responsibility matrices, escalation chains, skill taxonomy (SFIA 9 + Agent Skills), and capacity planning per portfolio.', 'open', '2026-03-14 21:40:10.398', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('c47b12de-d9f9-4acf-8f5f-086f24ec1fb5', 'EP-a6b59105-ed04-4a28-a43d-ee0a49a1bcf0', 'Security & Vulnerability Agent', 'Autonomous AI security agent that continuously monitors the platform and generated code for vulnerabilities, misconfigurations, and compliance gaps. Operates as a workforce member with governed autonomy (trust lifecycle). Scans infrastructure (Docker configs, environment variables, exposed endpoints), dependencies (extends SBOM CVE pipeline), and code (OWASP Top 10, injection patterns, auth bypasses). Findings surface as GRC Incidents with severity ratings and actionable remediation. Integrates with Build Studio to gate code promotion on security review. Reports to the security dashboard on /platform.', 'open', '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('af342aaf-bdc5-4d64-a1f1-2ba5a3a0b0ec', 'EP-bcd49200-247b-49dd-9997-363d8a4eeb93', 'UI/UX Usability Standards', 'Establish and enforce platform-wide usability standards based on WCAG 2.1 AA. All UI surfaces (admin shell, storefront, portal, public pages) must meet minimum contrast ratios, readable typography, accessible interactive elements, and theme-aware color usage. Branding configuration must validate against these standards — rejecting or warning on non-compliant color combinations. Standards are enforced at theme derivation time and audited via automated tests. This prevents the class of bugs where hardcoded dark-mode-only styles (e.g. text-white) render unreadable in light mode, and ensures user-configured brand colors produce accessible interfaces.', 'open', '2026-03-21 00:35:09.734', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('e70d2aac-39f3-41a9-a0be-6a559e929e7c', 'EP-c48350bc-6658-4cd6-a40c-936efe41c06a', 'Rich CRM & Customer Lifecycle', 'Foundation CRM models: extend CustomerContact (firstName/lastName split, phone, jobTitle, linkedinUrl, source, doNotContact), many-to-many Contact↔Account via ContactAccountRole junction table, extend CustomerAccount (website, employeeCount, annualRevenue, currency, parentAccountId, lifecycleState), full-text search vectors, duplicate prevention at creation. Research-backed: Twenty, Attio, SuiteCRM, Frappe patterns.', 'done', '2026-03-21 00:34:57.113', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('3190c646-b40b-4137-819a-9b02fde03a27', 'EP-c7d7ca4d-c1cd-4da4-b8da-02e5c6822cea', 'CRM Sales Pipeline & Quote-to-Order', 'Full sales pipeline from prospect engagement through quote-to-order conversion. Uses Engagement model (not separate Lead table) linked to existing CustomerContact — avoids Salesforce conversion nightmare. Buyer-centric pipeline stages (qualification→discovery→proposal→negotiation→closed) with dormant auto-flagging. Itemised quoting with line + header discounts (ERPNext/Odoo pattern). Unified polymorphic Activity timeline with system auto-logging. Research-backed design: no data duplication, progressive disclosure, duplicate prevention at creation.
INSERT INTO public."Epic" VALUES ('0e1e05c1-d164-4b55-981c-242721c843b4', 'EP-cb3d7a86-ad4d-4bd7-ae7a-8961bc94aa4b', 'ITSM Module', 'Native incident, problem, known error, change request, and service request management — purpose-built for small-to-mid sized companies who cannot justify a full ServiceNow deployment. Implements the IT4IT Detect to Correct (D2C) and Request to Fulfill (R2F) value streams within the platform.', 'open', '2026-03-21 00:34:52.23', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('541c6fb9-14f0-4d7c-aa0f-265198e10a0b', 'EP-d054c329-b06d-4c46-b1e9-41efc5d93535', 'UI/UX Usability Standards', 'Establish and enforce platform-wide usability standards based on WCAG 2.1 AA. All UI surfaces (admin shell, storefront, portal, public pages) must meet minimum contrast ratios, readable typography, accessible interactive elements, and theme-aware color usage. Branding configuration must validate against these standards — rejecting or warning on non-compliant color combinations. Standards are enforced at theme derivation time and audited via automated tests. This prevents the class of bugs where hardcoded dark-mode-only styles (e.g. text-white) render unreadable in light mode, and ensures user-configured brand colors produce accessible interfaces.', 'open', '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('478beb91-1286-4b24-b7ef-0ec0fdd038ac', 'EP-d6872993-c3d0-4049-a1f4-3d4e40eb59ee', 'SBOM Management', 'Software Bill of Materials tracking using CycloneDX 1.6 JSON as the canonical format. Components are keyed by PURL (Package URL spec). CVE intelligence is sourced from OSV.dev (primary, PURL-native), NVD via CPE (fallback for commercial components), and CISA KEV as a weekly overlay that elevates any actively-exploited vulnerability to critical severity regardless of CVSS score. Implements two release gates: GATE-044 (every critical CVE must have a linked backlog remediation item) and GATE-045 (critical active CVE blocks release unless suppressed with an HR-200 decision record). SBOM components are rescanned weekly. Lives in the R2D (Requirement to Deploy) value stream — Design & Develop and Accept & Publish Release phases.', 'open', '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('eb66e53b-5444-40ab-8c5d-a13d882a0f3a', 'EP-f1880a0b-85cb-443b-83bb-4d33788227be', 'Neo4j + Digital Product Backbone', 'Establish Neo4j as the graph store for the Digital Product Backbone. Model cross-domain relationships (concept-to-operational), provider/consumer dependencies, and IT4IT data objects. This is the foundation for EA Modeler, impact analysis, and infrastructure registry.', 'open', '2026-03-21 00:34:52.23', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('207443fc-5596-47af-8d4e-54635f35fca6', 'EP-DMR-001', 'Replace Ollama with Docker Model Runner', 'Migrate local LLM inference from a custom Ollama Docker container to Docker Model Runner (built into Docker Desktop 4.40+). Eliminates the need for custom entrypoint scripts, VRAM management, model pulling logic, and GPU override configuration. Uses the standard OpenAI-compatible API at model-runner.docker.internal/v1.', 'done', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', NULL, NULL, '2026-03-22 02:44:05.905', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('b04d578b-2f95-4a22-beb4-fe30c4eca3db', 'EP-INSTALL-SWITCH-001', 'Allow switching between Consumer and Customizer install modes', 'Post-install mode switching and in-app contribution workflow. Mode switching: consumer to customizer (clone source, rebuild, preserve DB volumes) and customizer to consumer (switch to pre-built images, preserve DB). In-app PR workflow: platform UI for reviewing local customizations, creating GitHub PRs upstream, and pulling community updates — so users never need to touch git directly. The contribution process should be part of the platform UX, not a developer-only workflow.', 'open', '2026-03-22 04:13:42.461', '2026-03-22 04:13:42.461', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('7a5be275-150f-431e-8192-7bc570c64f38', 'EP-PROD-BUILD-001', 'Production Build and Install Path', 'Fix the production Docker build pipeline so the installer delivers pre-compiled images instead of building from source. Current install downloads source and compiles — this is unnecessary since the sandbox instance already has source. Fix type errors that only surface during production compilation. Separate developer install (source + tools) from user install (pre-built images only).', 'done', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', NULL, NULL, '2026-03-22 05:03:10.03', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('e47ba91c-72d9-415a-8a54-dcd2ba5de499', 'EP-DEVCONTAINER-001', 'VS Code Dev Container for Platform Development', 'Create a persistent Dev Container configuration so all developers (and Claude Code) work inside a standardized container environment via the VS Code Dev Containers extension. Source is volume-mounted so edits persist. Separate from the ephemeral Build Studio sandbox — this is the human developer workshop, not the AI factory floor. Ensures consistent tooling (Node, pnpm, git, Prisma, tsx) across all contributors. Anyone who installs the Customizable mode and the Dev Containers extension gets a ready-to-go IDE experience. Includes devcontainer.json, a dedicated dev service in compose, and all necessary extensions/settings pre-configured.', 'open', '2026-03-22 05:20:51.046', '2026-03-22 05:20:51.046', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a86x08334co79il8sdg1', 'EP-UI-THEME-001', 'Theme & Branding Modernization', 'Create a resilient theme-system foundation with configurable color/branding presets from a curated set of company styles.', 'open', '2026-03-22 02:07:45.657', '2026-03-22 20:37:36.85', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn1x45000000sgu4dh1q376k', 'EP-STORE-OPS', 'Unified Hours of Operation Setup', 'Dedicated operating hours step in the onboarding flow (after org-settings, before storefront). Captures business operating schedule once, feeds both BusinessProfile (deployment windows) and ProviderAvailability (storefront booking). Smart defaults from archetype/industry. Reusable hours editor component for post-setup changes. Spec: docs/superpowers/specs/2026-03-22-unified-hours-of-operation-design.md', 'open', '2026-03-22 15:34:50.448', '2026-03-22 18:20:57.988', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn1x450u0001sgu4m1jiutxb', 'EP-STORE-SCHED', 'Recurring Class/Session Scheduling', 'Timetable builder for training academies, yoga studios, fitness classes, and other class-based businesses. Recurring sessions within operating hours, capacity per session, enrollment/waitlists, instructor assignment, auto-generation of future instances. Depends on EP-STORE-OPS delivering the operating hours foundation. Architecturally distinct from appointment-based booking (1:many with capacity constraints).', 'open', '2026-03-22 15:34:50.478', '2026-03-22 18:20:58.015', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8at08344co7lz9f22cc', 'EP-UI-A11Y-001', 'Dark-Theme Usability & Accessibility Policy', 'Establish and enforce WCAG 2.1 AA contrast standards, minimum font sizes, and surface separation rules tailored to the platform''s dark theme. Applies to all future development and admin configuration screens.', 'open', '2026-03-22 02:07:45.797', '2026-03-22 20:37:36.926', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn14a8ch083a4co7vjm2iqfy', 'EP-LLM-LIVE-001', 'Live LLM Conversations', 'Replace canned responses in the co-worker panel with real AI inference via configured providers. Generalizes the existing profiling call infrastructure into a chat-capable inference pipeline.', 'open', '2026-03-22 02:07:45.857', '2026-03-22 20:37:36.942', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."Epic" VALUES ('cmn28ruj80000pwu4jksrlnwj', 'EP-AI-UX', 'AI Provider Configuration UX Refactor', 'Simplify the AI provider configuration experience. The current UI has grown organically with many sections (model families, discovered models, model profiles, test/sync buttons) that made sense incrementally but now create unnecessary complexity. Key issues:
INSERT INTO public."BacklogItem" VALUES ('5db5a922-9a0d-4839-9954-afe37e413567', 'BI-DMR-001', 'Remove ollama service from docker-compose.yml', 'done', 'product', 'Remove ollama container, volumes, entrypoint, healthcheck. Add LLM_BASE_URL env var to portal. Remove ollama dependency from portal depends_on.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 1, NULL, NULL, '207443fc-5596-47af-8d4e-54635f35fca6', NULL, 1, NULL, NULL, NULL, '2026-03-22 02:44:05.905', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d77d2ebb-173f-4449-8564-1109d1d0a57f', 'BI-DMR-002', 'Rewrite embedding.ts for OpenAI-compatible API', 'done', 'product', 'Switch from Ollama /api/embeddings to /v1/embeddings. Use OpenAI response format {data:[{embedding}]}. Update model reference to ai/nomic-embed-text.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 2, NULL, NULL, '207443fc-5596-47af-8d4e-54635f35fca6', NULL, 1, NULL, NULL, NULL, '2026-03-22 02:44:05.905', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('da0991a7-11bc-4a24-b5b8-48f1156d324f', 'BI-DMR-003', 'Update provider adapter and health checks', 'done', 'product', 'Rewrite adapter-ollama.ts parseDiscoveryResponse to handle both OpenAI {data} and legacy {models} formats. Update ollama.ts health checks from /api/tags to /v1/models.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 3, NULL, NULL, '207443fc-5596-47af-8d4e-54635f35fca6', NULL, 1, NULL, NULL, NULL, '2026-03-22 02:44:05.905', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('aefc1ee0-2966-4650-abf6-7c80ce4e160e', 'BI-DMR-004', 'Update install scripts for Docker Model Runner', 'done', 'product', 'Replace ollama model pull with docker model pull. Use ai/ namespace model IDs. Remove GPU override generation. Remove ollama wait loops.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 4, NULL, NULL, '207443fc-5596-47af-8d4e-54635f35fca6', NULL, 1, NULL, NULL, NULL, '2026-03-22 02:44:05.905', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('e1eac0af-40ae-4cc1-b65a-3d6beb348ef0', 'BI-PROD-BUILD-001', 'Fix all TypeScript type errors in production build', 'done', 'product', 'Resolve type errors that only surface during next build (production compilation). Includes: IntegrationCard Decimal import, prerendering database calls, module resolution issues.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 1, NULL, NULL, '7a5be275-150f-431e-8192-7bc570c64f38', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('4619c945-08b3-4c44-9978-c418b8542e5e', 'BI-PROD-BUILD-002', 'Fix migration ordering for clean deploy', 'done', 'product', 'Resolve 5 duplicate migration timestamps and 1 dependency ordering issue (execution_adapter before execution_recipe). All 79 migrations now apply cleanly on fresh database.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 2, NULL, NULL, '7a5be275-150f-431e-8192-7bc570c64f38', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
