INSERT INTO public."BacklogItem" VALUES ('eb33f192-53b5-4eab-bac9-bfbf52f2a39f', 'BI-2d331663-78fb-473c-974c-e1855626a980', 'Security Agent registration: register SecurityAgent as Agent entity in workforce registry with role=security_analyst, capabilities=[vulnerability_scan, code_review, dependency_audit, config_audit, incident_creation]. Trust level starts at Learning. Autonomy profile: can create findings/incidents autonomously, but remediation PRs require human approval (Practicing). RACI: Responsible for scanning, Accountable to platform admin.', 'open', 'portfolio', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('a3724a0d-8572-420e-926e-3afaf432c30c', 'BI-21bb982e-ab06-4615-a672-d54b2fd0644b', 'Infrastructure security scanner: scheduled scan of Docker compose files, environment variable exposure (.env patterns, secrets in config), port exposure, TLS configuration, CORS policies, CSP headers, and authentication endpoint hardening. SecurityFinding model — findingType enum (infrastructure/dependency/code/config), severity (critical/high/medium/low/info), cweId (CWE reference), title, description, affectedResource, remediationGuidance, status (open/triaged/remediated/accepted_risk/false_positive), detectedAt, resolvedAt. Findings auto-create GRC Incidents when severity >= high.', 'open', 'portfolio', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('b6e2bec4-b9d3-4574-8c7c-c24c028dadce', 'BI-PROD-BUILD-004', 'Set up Docker image registry for pre-built images', 'done', 'product', 'Push production images to a registry (GHCR or Docker Hub). Install script pulls pre-built images instead of building from source.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 4, NULL, NULL, '7a5be275-150f-431e-8192-7bc570c64f38', NULL, 1, NULL, NULL, NULL, '2026-03-22 04:13:42.461', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('bc27df60-040c-49d8-bb6f-5658856db692', 'BI-PROD-BUILD-005', 'Add CI/CD pipeline for production image builds', 'done', 'product', 'GitHub Actions workflow that builds and pushes Docker images on release tags. Includes typecheck gate to catch errors before image publish.', '2026-03-22 02:44:05.905', '2026-03-22 02:44:05.905', 5, NULL, NULL, '7a5be275-150f-431e-8192-7bc570c64f38', NULL, 1, NULL, NULL, NULL, '2026-03-22 04:13:42.461', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
