INSERT INTO public."BacklogItem" VALUES ('cmn14a8dv083r4co746wfg8so', 'BI-EXEC-004', 'Implement proposal execution engine', 'done', 'product', 'On approval: map actionType + parameters to existing server actions (createBacklogItem, etc.). Execute with approving user auth context. Record executedAt, resultEntityId or resultError. Post confirmation in thread.', '2026-03-22 02:07:45.907', '2026-03-22 20:37:36.981', 4, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8di083n4co7hu6es2pm', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8h1084x4co7ue13aq7m', 'BI-MOB-020', 'Profile + settings screen', 'open', 'product', 'More tab profile screen showing current user info, role, and capabilities. Settings for notification preferences, biometric unlock toggle, cache management (clear cache), and app version info.', '2026-03-22 02:07:46.021', '2026-03-22 20:37:37.062', 10, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8gb084n4co7m6ht7r0d', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
