INSERT INTO public."BacklogItem" VALUES ('cmn14a8bp08374co77h1p74i7', 'BI-PROD-011', 'Audit and remediate existing admin/platform screens for contrast compliance', 'done', 'product', 'Sweep all /platform, /admin, and /ea screens. Replace any remaining #555566 with #8888a0. Bump undersized text. Verify form inputs, buttons, and labels meet the new minimums.', '2026-03-22 02:07:45.829', '2026-03-22 20:37:36.934', 3, 'cmn14a862082q4co7oh5nh8uq', NULL, 'cmn14a8at08344co7lz9f22cc', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8br08384co7quo0vngu', 'BI-PROD-012', 'Create dark-theme development guidelines for future feature work', 'open', 'product', 'Write developer-facing guidelines covering: surface hierarchy rules (bg < surface-1 < surface-2), border contrast, focus indicators, disabled-state contrast, and how to validate with contrast-checker tools. Include in onboarding docs.', '2026-03-22 02:07:45.831', '2026-03-22 20:37:36.936', 4, 'cmn14a862082q4co7oh5nh8uq', NULL, 'cmn14a8at08344co7lz9f22cc', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8dr083p4co7hle28849', 'BI-EXEC-002', 'Build proposal creation from agent inference', 'done', 'product', 'Parse LLM tool-use responses into AgentActionProposal records. Define tool schemas: create_backlog_item, update_lifecycle, create_ea_element, etc. System prompts include available tools based on user capabilities.', '2026-03-22 02:07:45.903', '2026-03-22 20:37:36.978', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8di083n4co7hu6es2pm', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8fd084b4co77zyo5k97', 'BI-REST-017', 'SSE stream migration (replace /api/agent/stream with /api/v1/agent/stream)', 'done', 'product', 'Migrate SSE stream endpoint to /api/v1/agent/stream accepting both JWT and session auth. Deprecate old /api/agent/stream route. Ensure backward compatibility during migration period.', '2026-03-22 02:07:45.961', '2026-03-22 20:37:37.021', 17, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8e3083u4co7t1ph5k8v', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8fs084e4co79zhirc5y', 'BI-MOB-002', 'Expo Router tab navigation (Home, Ops, Portfolio, Customers, More)', 'open', 'product', 'File-based routing with Expo Router. Bottom tab navigator with five tabs: Home (workspace), Ops, Portfolio, Customers, More. Stack navigators nested within each tab for drill-down screens.', '2026-03-22 02:07:45.976', '2026-03-22 20:37:37.028', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8gs084t4co7sw64gf8c', 'BI-MOB-016', 'Agent co-worker FAB (route-aware specialist, SSE streaming, thread history)', 'open', 'product', 'Floating action button persistent across all tabs. Routes to correct specialist based on current screen context (Ops → ops-coordinator, Portfolio → portfolio-advisor). Real-time SSE streaming in foreground. Push notification for background responses. Thread history synced with web.', '2026-03-22 02:07:46.012', '2026-03-22 20:37:37.057', 6, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8gb084n4co7m6ht7r0d', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8cn083b4co73v5tnrzj', 'BI-LLM-001', 'PlatformConfig schema + AgentMessage providerId + callProvider inference module', 'done', 'product', 'Extract the private callProviderForProfiling from lib/actions/ai-providers.ts into a shared lib/ai-inference.ts module. Generalize into callProvider(providerId, modelId, messages[], systemPrompt) supporting multi-turn chat. Return { content, inputTokens, outputTokens, inferenceMs }.', '2026-03-22 02:07:45.863', '2026-03-22 20:37:36.945', 1, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ch083a4co7vjm2iqfy', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8bn08364co7y4qu9xav', 'BI-PROD-010', 'Establish minimum font-size policy — 10px floor for all UI text', 'done', 'product', 'Audit all inline styles and Tailwind classes. No text element may be smaller than 10px. Form labels: 12px minimum. Form inputs and buttons: 13px minimum. Document in CLAUDE.md and component guidelines.', '2026-03-22 02:07:45.827', '2026-03-22 20:37:36.933', 2, 'cmn14a862082q4co7oh5nh8uq', NULL, 'cmn14a8at08344co7lz9f22cc', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
