INSERT INTO public."BacklogItem" VALUES ('cmn14a8f808494co7iiiau45j', 'BI-REST-015', 'REST API test suite (Vitest + supertest, matching web test framework)', 'done', 'product', 'Comprehensive test suite for all REST endpoints using Vitest + supertest. Test auth flows, CRUD operations, pagination, error responses, capability gates. Matches existing web test conventions.', '2026-03-22 02:07:45.956', '2026-03-22 20:37:37.018', 15, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8e3083u4co7t1ph5k8v', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
