INSERT INTO public."BacklogItem" VALUES ('cmn14a8bc08354co74ywuvrnp', 'BI-PROD-009', 'Define dark-theme contrast standards — WCAG AA minimums for dark backgrounds', 'done', 'product', 'Document colour contrast requirements: 4.5:1 for normal text, 3:1 for large text against #0f0f1a and #1a1a2e surfaces. Establish token palette: --dpf-muted (#8888a0, ~5:1), labels (#c0c0d8, ~7:1), secondary (#b0b0c8, ~6:1). No text may use colours below 4.5:1 on dark surfaces.', '2026-03-22 02:07:45.816', '2026-03-22 20:37:36.931', 1, 'cmn14a862082q4co7oh5nh8uq', NULL, 'cmn14a8at08344co7lz9f22cc', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8gr084s4co7xn1mtfnd', 'BI-MOB-015', 'Customer list + detail + edit', 'open', 'product', 'Customers tab with searchable, filterable customer list. Customer detail screen showing contacts, accounts, and history. Edit capability for customer fields with capability-gated access.', '2026-03-22 02:07:46.011', '2026-03-22 20:37:37.055', 5, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8gb084n4co7m6ht7r0d', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('19eba8d4-65d0-4b23-bed0-a5cee7e0f577', 'BI-023d604f-56f1-4cf4-9872-8a9f1bdc5c56', 'Invoice data model and sequential numbering', 'open', 'product', 'Create Invoice and InvoiceLineItem Prisma models with sequential numbering (INV-2026-0001). Support invoice types: standard, credit_note, proforma, recurring_instance. Include source tracking (sales_order, storefront_order, recurring, manual), tax calculation per line item, and ERP sync status fields. Add server actions: createInvoice, updateInvoice, approveInvoice, voidInvoice.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('db36db5c-cfa5-4fe5-b921-21c3e270504a', 'BI-0a8e21e2-8c3f-46ea-aed6-7dbd23a875ab', 'Invoice lifecycle and payment recording', 'open', 'product', 'Implement invoice status workflow: draft → approved → sent → viewed → partially_paid → paid (also overdue, void, written_off). Build Payment model with inbound/outbound direction, PaymentAllocation for split payments across invoices. Support payment methods: bank_transfer, card, cash, cheque, direct_debit, stripe. Auto-calculate amountDue = totalAmount - sum(allocations). Server actions: recordPayment, allocatePayment, refundPayment.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d5e826c1-6d9a-4987-90a9-0876b974d305', 'BI-8b9feefb-c0d9-43f4-8dba-4b1373839d42', 'Invoice generation from sales orders and storefront orders', 'open', 'product', 'Auto-generate invoices when SalesOrder status = confirmed (from EP-CRM-SALES-001 quote acceptance) and when StorefrontOrder is completed. Map line items, customer details, and payment terms. Handle tax calculation based on customer jurisdiction. Idempotent — do not duplicate invoices for the same source order.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('4245edbb-a8d8-4090-9088-f20a9a7f1bb1', 'BI-8c9211fb-2117-4950-aa10-903449b7a20a', 'Invoice sending, Pay Now portal, and view tracking', 'open', 'product', 'Generate invoice PDF (filename: Invoice-{NUMBER}-{CLIENT}.pdf). Send via email with embedded Pay Now button linking to a secure payment page — the payment link is the hero, PDF is secondary download. Payment page requires zero account creation (enter card/bank details, pay, done). Page branded with business storefront styling. Track email open, page view, and payment status. 5 template styles mapped to archetype categories (professional, trade, creative, nonprofit, minimal). Brand customisation: logo, primary colour, font. Inline template editing — never navigate to settings. Precedent: 40% same-day payment with payment links vs 5% for traditional invoices (Stripe data).', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('e3620fd2-38c3-46e4-9bd1-7bc28b1ddcb4', 'BI-272aa2f9-0652-4b83-b9d2-ca362a51aaef', 'Invoicing UI — 60-second invoice creation and admin views', 'open', 'product', 'Single-page invoice creation (no multi-step wizard). Customer auto-complete with recents at top. Line item quick-add with product/service picker. Smart defaults: currency from customer, terms from customer or org, tax from org. Save and Send as primary action. Pre-fill from source orders with zero additional input. Shell routes: /finance/invoices (list with Viewed But Not Paid status column, filters: status, customer, date, overdue), /finance/invoices/new, /finance/invoices/[id] (detail with payment history, send, void). Dashboard cards: outstanding, overdue, paid this month. Precedent: FreshBooks wins because invoice creation is fast. QB 2025 redesign backlash when it went from 1 min to 5 min.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('e9453e66-d81c-49d4-b82b-7d089dd4d5e6', 'BI-f532d48a-29fb-4d56-921d-1b0c23aa6953', 'Supplier model, bill capture with OCR, and approval routing', 'open', 'product', 'Create Supplier model (name, contact, tax ID, payment terms, bank details, status). Create Bill and BillLineItem models (BILL-2026-0001 sequential). Bill lifecycle: draft → awaiting_approval → approved → partially_paid → paid → void. OCR bill capture: dedicated email inbox per org (bills@{slug}.odpf.io), extract supplier/date/lines/totals/tax. Side-by-side display: original document left, extracted data right. Quick correction UX (click to edit, tab between fields). Learn from corrections per supplier. Multi-step approval routing: rules by amount threshold, supplier, category (e.g. under £500 auto-approved, £500-5K manager, 5K+ director). Approvers get email with approve/reject buttons — no login required (secure token link). Precedent: ApprovalMax (19K businesses) exists because Xero/QB approval is inadequate; Dext OCR ~85% accurate, correction speed matters more than marginal accuracy. Admin UI: /finance/suppliers, /finance/bills.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('8c7e059c-cd25-4e95-a096-8a33e8184706', 'BI-6d086d21-92d1-4f11-bba5-89bd053ca1de', 'Purchase order workflow (optional, archetype-driven)', 'open', 'product', 'POs disabled by default for service archetypes, enabled for trades/construction/retail. Toggleable in settings. Create PurchaseOrder and PurchaseOrderLineItem models (PO-2026-0001 sequential). PO lifecycle: draft → sent → acknowledged → received → cancelled. PO creation under 2 minutes: pick supplier, add lines, send. Primary value: PO-to-bill conversion — when supplier invoice arrives, match to PO, auto-populate bill, catch pricing discrepancies. No 3-way matching (PO → goods receipt → bill) in V1 — most SMBs under 20 employees do not use it; add later for growing businesses. Admin UI: /finance/purchase-orders.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('aafb6aa0-2bc0-466f-97ac-8736b810f06c', 'BI-aee2d8e9-9089-4aed-a6e7-631ef5bcbe67', 'Payment runs and batch outbound payments', 'open', 'product', 'Build payment run workflow: select approved bills due within date range, group by supplier with option to consolidate multiple bills per supplier into one payment (addresses Xero gap). Generate BACs file (UK) or ACH/Nacha file (US) for bank upload. Approval gate before execution (separate from bill approval). Record outbound payments and allocate to bills. Support partial payment of bills. Include expense claim reimbursements in the same payment run system. Admin UI: /finance/payment-runs with history and audit trail.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 8, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('db2e9767-3178-42ed-a134-60781dad812d', 'BI-4624f7d3-e1e1-4e31-beaf-0137137a0916', 'Bank account model and CSV feed import', 'open', 'product', 'Create BankAccount model (name, bank, account number, sort code, IBAN, currency, type, opening balance, current balance). Create BankTransaction model for imported statement lines (date, description, amount, balance, match status). CSV import with format auto-detection (date format, column mapping, debit/credit vs signed amounts) for major UK/US bank formats. Critical: one bad row must NOT fail the entire import — report errors, import the rest (precedent: silent CSV import failure is a known high-abandonment point). Admin UI: /finance/banking with account list and transaction feed as primary view (code-as-you-go, not monthly reconciliation).', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 9, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('377069de-9e2d-4b6f-8ef9-520e18b2cbc1', 'BI-bd2dd87c-5567-4aa9-aad7-3c0adae89cf6', 'Bank reconciliation matching engine with rules and AI assist', 'open', 'product', 'Code-as-you-go workflow: bank transactions appear in a feed, user matches/categorises each one. Suggested matches with confidence indicator (green = high confidence). One-click confirm for auto-matched transactions. Bank rules from day one: match by payee name (contains/exact), amount (range/exact), description keywords. Rules auto-apply account code, tax rate, description. Create Rule From This Transaction button on every bank line. Rules auto-suggested after 3+ similar manual categorisations. AI-assisted matching: learn from user reconciliation history, improve confidence over time, auto-categorise recurring transactions — but never auto-confirm without user review. Precedent: Xero JAX reduced bookkeeper time from 7hrs/week to 30 minutes with 80%+ auto-match rate. Admin UI: /finance/banking/[id]/reconcile.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 10, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('8de5b333-a7cc-48bc-898e-b4b6d6753619', 'BI-53c496cc-751f-494b-b2c9-18f11133fed9', 'Cash position dashboard and cash runway', 'open', 'portfolio', 'Real-time cash position across all bank accounts — the single most important financial metric (precedent: universal across SMB dashboard research). Cash flow forecast: 30/60/90-day forward view based on receivables due dates + payables due dates + recurring schedules + payroll dates. Cash runway metric: At current burn rate, cash lasts X months — trivially computed, critically useful for SMB owners. Simple what-if: What if Invoice X is paid 30 days late? What if I hire at Y salary? (this is where Float wins over built-in tools). Present the answer as a number first, visualisation second: You have £X. Based on what is owed in and out, you will have £Y in 30 days. Highlight projected cash shortfalls. Currency breakdown for multi-currency.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 11, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('bd03f36d-7cd0-4c97-a090-81b39bae32a6', 'BI-ee7dbfc1-7fcb-4678-b5b9-da405d75f9ac', 'Recurring billing schedules and auto-invoicing', 'open', 'product', 'Create RecurringSchedule and RecurringLineItem models. Support frequencies: weekly, fortnightly, monthly, quarterly, annually. Auto-generate invoices on schedule (cron job or event-driven). Track nextInvoiceDate, auto-advance after generation. Schedule lifecycle: active → paused → cancelled → completed. Link generated invoices back to schedule with sourceType=recurring. Admin UI: /finance/recurring.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 12, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('10e7d6ad-7500-44a8-8b34-9aba4387aa5e', 'BI-681c6a06-8fce-4c20-84de-6032473f63c2', 'Smart default dunning with pre-due reminders', 'open', 'product', 'Default dunning active out of the box — no setup required (precedent: biggest barrier to credit control is emotional; automation removes friction of chasing money). Default sequence: Day -3 friendly heads-up BEFORE due date (significantly improves on-time payment but most users never configure this), Day +7 first overdue with payment link, Day +14 firm reminder, Day +30 final notice + account flagged, Day +45 escalation task for owner. Every reminder includes Pay Now link. Archetype-aware defaults: nonprofits dunning off, trades aggressive (+3/+7/+14/+30), professional services standard. Weekly email digest to owner: You have £X overdue, top 5 customers. Configurable but works perfectly with defaults. Admin config: /finance/settings/dunning.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 13, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('b35f3907-79e5-43c2-9f5f-e2165978e460', 'BI-04088641-c368-4df1-8725-17ce9673b4f9', 'Aging analysis and actionable aged debtors widget', 'open', 'product', 'Aged debtors report as a dashboard widget, not buried in a reports menu (precedent: this is the core credit control report, run weekly by disciplined businesses). Current/30d/60d/90d/120d+ buckets per customer. Click any row → customer detail with Send Reminder action (payment link included). Aged creditors: same structure for supplier bills. Customer statement generation (PDF) with all transactions and balance. Add paymentTerms to CustomerAccount. No credit limit enforcement in V1 — almost no SMB sets or uses credit limits even when available; investment goes to better automated reminders instead. Admin UI: /finance/reports/aged-debtors, /finance/reports/aged-creditors.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 14, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('57659480-122a-4cb2-8863-e87113e2b13a', 'BI-42bcd33d-41ad-4cbc-aff3-3e104a3ca0a6', 'Mobile-first expense claims with receipt capture and approval', 'open', 'product', 'Phone-camera receipt capture as primary input (non-negotiable per Expensify/Dext precedent): take photo → auto-extract amount, date, vendor, category. Show original receipt alongside extracted data for verification. Learn from corrections per vendor. Create ExpenseClaim and ExpenseItem models (EXP-2026-0001 sequential). Claim lifecycle: draft → submitted → approved → rejected → paid. Categories: travel, meals, accommodation, supplies, mileage, other (archetype-extensible). Approval routing by amount threshold: under £25 auto-approved, £25-500 manager, £500+ director (configurable). Approvers get email with expense + receipt + approve/reject buttons — no login required (secure token link). Reimbursement via payment run system (same as supplier payments). Employee portal: /portal/expenses (mobile-optimised). Manager view: /finance/expense-claims.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 15, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('422c35b7-f46f-437e-b333-69a16d50604f', 'BI-d4d1428c-5d6d-4115-b89a-83610a287b86', 'Duplicate prevention at contact creation: fuzzy match on email, name, phone with confidence scores', 'done', 'portfolio', NULL, '2026-03-21 00:39:09.414', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('370504db-ca33-4e42-9a91-1c7424c2f492', 'BI-5c30dec8-9425-491b-9449-fc9197129cc6', 'Customer lifecycle server actions: createProspect, qualifyAccount, startOnboarding, activateAccount, markAtRisk, suspendAccount, closeAccount', 'done', 'portfolio', NULL, '2026-03-21 00:39:09.414', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('61bdd160-a102-4ae7-9e0f-f0ba4e9d536d', 'BI-bdd37cc9-dab9-44e8-b73b-685c2cd5d39d', '/customer route: account list with lifecycle state filter, search, contact details, timeline layout', 'done', 'product', NULL, '2026-03-21 00:39:09.414', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('67d2d7bf-8a54-4e62-a6b4-1523e316ec4a', 'EP-FOUND-OPS-018', 'Snapshot retention cleanup task (7-day raw, 90-day hourly rollup)', 'open', 'portfolio', NULL, '2026-03-21 18:54:17.588', '2026-03-22 02:35:28.707', 18, NULL, NULL, NULL, 'spec', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('23a9bb85-38b0-4a54-9c2f-72483633b0ce', 'BI-0fa7dcc0-f1b5-42b4-9ab1-a5f3fe8e792f', 'Financial reporting — four-widget dashboard and plain-language reports', 'open', 'portfolio', 'Default finance dashboard shows exactly four widgets (precedent: these drive 90% of SMB decisions): (1) Cash position — current bank balance(s) with trend arrow, (2) Cash flow forecast — 30/60/90-day forward, (3) Outstanding invoices — total owed, overdue count, worst-offender customer, (4) P&L summary — this month vs last, revenue and expenses with trend. Additional widgets available but hidden by default: aged debtors, aged creditors, budget vs actual. Plain language by default: Money In not Revenue, Money Out not Expenditure, Money Owed To You not Accounts Receivable. Accountant mode toggle for proper terminology. Every report has a one-sentence summary: You made £12,400 profit this month, up 8%. Core reports: P&L, Balance Sheet (via ERPNext), aged debtors/creditors, cash flow, VAT summary. No custom report builder (SMBs never use them). Export to CSV/PDF.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 16, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('ba368761-6272-4254-9918-3fde67fa3cc1', 'BI-4309e0dc-96d6-46b7-9fa2-2cb0e8522a05', 'Fixed asset register and depreciation', 'open', 'product', 'Create FixedAsset model (name, category, purchase date/cost, depreciation method, useful life, residual value, book value, accumulated depreciation, status, serial number, assigned employee). Depreciation methods: straight_line, reducing_balance. Monthly depreciation calculation (batch job). Asset lifecycle: active → disposed → written_off. Disposal with gain/loss calculation. Admin UI: /finance/assets. ERP sync for GL posting of depreciation journals.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 17, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('c2faf27e-b387-4490-a27f-90d4d621983f', 'BI-f8175134-0253-44f9-b53b-d6e0c6d6b276', 'Multi-currency — per-transaction, transparent, not premium-gated', 'open', 'product', 'Multiple currencies per customer/supplier (precedent: QB one-currency-per-customer model is universally hated — no duplicate Customer A GBP / Customer A USD profiles). Every invoice/bill can use any currency regardless of customer default. Cross-currency payments handled natively — no dummy clearing accounts. Organization base currency set during onboarding. Auto-fetch daily exchange rates (ECB or configurable). Manual override per transaction (bank rates differ from market). Every payment shows: invoice currency, payment currency, rate used, base currency equivalent. Realised FX gain/loss on payment allocation. Unrealised FX on period-end revaluation with full line-by-line detail. FX summary report. Multi-currency bank accounts. Not gated behind a premium tier (UK businesses with US clients is baseline, not edge case).', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 18, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('ff603341-e89a-41ab-bc6b-b03839524f3a', 'BI-51fe93a8-530a-424f-aa7e-b379c2c1a86b', 'Archetype-driven financial profile templates', 'open', 'product', 'Map each storefront archetype to a financial profile: chart of accounts template, default tax configuration (VAT registered vs not, rate bands), default payment terms, invoice template style, expense categories, dunning defaults, recurring billing toggle. Financial profile applied during first-run setup wizard (after storefront archetype selection). Include UK and US variants for tax and chart of accounts. Store templates in packages/finance-templates.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 19, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('f81b99da-6e50-4b39-b9fe-0262e5c55c0c', 'BI-efb9a762-5c76-4859-8b23-7cc41d156e4c', 'Financial setup wizard — first win in under 5 minutes', 'open', 'product', '3 questions maximum during setup: business type (already answered via storefront archetype), VAT registered (yes/no), base currency (GBP/USD). Auto-generate everything else from archetype profile — user sees confirmation: Based on your business type, we have set up your finances. You can customise later. Do NOT show the full chart of accounts during setup (precedent: 85% abandonment rate in complex setup, COA is the #1 barrier). Skip opening balances entirely — add later when the accountant gets involved. Bank connection NOT required to start. Prompt first win: Send your first invoice or Record your first expense. One-click demo data option: sample customer + pre-filled invoice. Progressive disclosure: Week 1 prompts Connect your bank, Add your first supplier. Month 1 prompts Review your first P&L. Advanced features (POs, assets, multi-currency) discoverable but not promoted until signalled. Revisitable from /finance/settings.', '2026-03-21 00:35:06.734', '2026-03-22 02:35:28.707', 20, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d2590d12-c9b9-483c-b903-d1e2ed476b07', 'EP-STORE-003', 'Storefront Booking Calendar — Availability, Slot Computation & Scheduling Patterns', 'open', 'epic', 'Availability-first architecture with computed slots for booking-enabled storefronts. Three scheduling patterns (slot-based, class/capacity, recurring). ServiceProvider + ProviderAvailability + BookingHold. Archetype-driven defaults. Spec: docs/superpowers/specs/2026-03-20-storefront-booking-calendar-design.md', '2026-03-21 03:33:45.95', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
