INSERT INTO public."BacklogItem" VALUES ('f80a6ddb-250c-493c-8c04-ec7f0e3a871c', 'BI-e73b924a-eb9d-428f-b016-9a804b3457ab', 'Dependency vulnerability continuous monitoring: extend SBOM CVE sync to run on configurable schedule (default: daily). When new critical/high CVEs are discovered, SecurityAgent autonomously creates SecurityFinding + GRC Incident + linked BacklogItem for remediation. Tracks time-to-remediate SLA per severity level. Dashboard widget showing dependency health trend over time.', 'open', 'portfolio', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('9384c04d-d835-4372-b3c3-98ab4b05bd9c', 'BI-1fe4a586-7d86-45c1-a7a1-557248eb1633', 'Code security review engine: OWASP Top 10 pattern matching against platform codebase and Build Studio generated code. Patterns: SQL injection (raw query detection), XSS (unsanitised output), CSRF (missing token validation), insecure deserialization, broken auth (hardcoded secrets, missing rate limits), SSRF (unvalidated URLs), path traversal. Uses AST analysis where possible, regex fallback. SecurityFinding created per pattern match with CWE reference and fix suggestion.', 'open', 'product', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('9a1e0940-0c21-4cc5-9017-b55a6785cdea', 'BI-1a83f6f3-c483-444e-9d53-625c73a2b335', 'Build Studio security gate: before code promotion from sandbox to production, SecurityAgent runs full scan (infrastructure + dependency + code). SecurityGateResult model — buildId FK, scanStartedAt, scanCompletedAt, findingsCount (by severity), gateStatus enum (passed/failed/warning), blockingFindings (array of SecurityFinding IDs). Gate fails if any critical finding exists. Warning if high findings exist. Results shown on Build Studio promotion dialog with drill-down to findings.', 'open', 'product', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('90349ecd-0bb3-4650-8d5a-a1616e1cb968', 'BI-436f6c77-472d-497b-8b0f-565f73cd675b', 'Secret detection and rotation tracking: scan for exposed secrets (API keys, tokens, passwords) in code, config files, environment variables, and git history. SecretFinding model extends SecurityFinding with secretType enum (api_key/token/password/certificate/private_key), exposureLocation, rotationRequired bool, rotatedAt. Alert pipeline: immediate notification to platform admin when secret detected. Integration with provider registry to flag affected AI provider tokens.', 'open', 'product', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('6675f7f8-c8d4-4824-bdfe-4aac9b7649f8', 'BI-7b12687e-bbb8-42db-939d-51bd4f6ba768', 'Security posture dashboard: /platform/security route showing real-time security health — open findings by severity (donut chart), findings trend over time (line chart), mean-time-to-remediate by severity, dependency vulnerability coverage %, infrastructure scan last-run status, Build Studio gate pass/fail rate, top 5 CWEs recurring, compliance obligation coverage for security-related GRC obligations. Exportable as PDF for audit evidence.', 'open', 'product', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('4575e2f8-5d55-455d-9b45-d6c0494ed30d', 'BI-409323b1-09d0-4eba-b0f2-f2aa84bfe76c', 'Automated remediation proposals: when SecurityAgent reaches Practicing trust level, it can generate remediation code patches for common patterns (dependency version bumps, CSP header fixes, input sanitisation wrappers, secret rotation scripts). Patches submitted as change proposals in Build Studio requiring human approval. Remediation linked back to SecurityFinding and GRC Incident for full audit trail. Tracks remediation success rate to inform trust lifecycle progression.', 'open', 'product', NULL, '2026-03-21 00:35:03.719', '2026-03-22 02:35:28.707', 8, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('fcfdf15d-416a-4b99-8d4d-708d777ae98c', 'BI-8ed631a0-9c03-4fa1-a069-faa86675c63a', 'SbomComponent model (Prisma): keyed on purl (unique, PURL spec e.g. pkg:npm/react@18.2.0), name, version, componentType enum (library|framework|container|firmware|device|os|application|service), originType (open_source|commercial|internal), supplier?, licenseExpression (SPDX string e.g. MIT OR Apache-2.0), sha256?, cpe? (for NVD matching); updatedAt for rescan SLA tracking', 'open', 'portfolio', NULL, '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('9311c65b-e6f7-461f-8d0f-a6b1c28ddd81', 'BI-a3e0e95b-2824-4d51-b745-8aaa592ceba1', 'ProductComponent join model (Prisma): DigitalProduct → SbomComponent many-to-many — digitalProductId FK, sbomComponentId FK, isDirectDependency bool, addedAt DateTime; composite unique on (digitalProductId, sbomComponentId); cascades delete when product or component is removed', 'open', 'portfolio', NULL, '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('dced3298-bb8e-44fb-9683-46e1d8a0e744', 'BI-ea7b80b3-3039-4454-ade6-65c8de238203', 'ComponentVulnerability model (Prisma): sbomComponentId FK, cveId (CVE-xxxx-xxxxx or GHSA-...), cvssScore Decimal?, cvssSeverity (critical|high|medium|low|none), inCisaKev bool (CISA KEV overlay — if true, effectiveSeverity = critical regardless of CVSS), vexStatus (not_affected|affected|fixed|under_investigation|suppressed), vexJustification?, patchedVersion?, suppressedAt?, suppressedBy (userId)?; unique on (sbomComponentId, cveId)', 'open', 'portfolio', NULL, '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cd8aee2b-268e-4199-8fa7-2e165be08968', 'BI-d5faf691-3a32-4aa5-900a-3f73a155fa18', 'SbomDocument model (Prisma): point-in-time CycloneDX snapshot — digitalProductId FK, serialNumber (urn:uuid:...), bomVersion Int, specVersion "1.6", documentJson (full CycloneDX 1.6 BOM as Json), generatedAt DateTime; read-only after creation; latest document drives the /inventory SBOM view', 'open', 'portfolio', NULL, '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('1d6cfa68-a8f2-42e6-8db3-97caab0d8258', 'BI-93c06075-4793-488d-9901-c7c2732cfc9f', 'CycloneDX 1.6 document generator: generateSbom(digitalProductId) server action — assembles valid CycloneDX 1.6 JSON (serialNumber urn:uuid:..., metadata.component from DigitalProduct, components[] with purl/type/name/version/licenses/hashes, vulnerabilities[] from ComponentVulnerability), persists as SbomDocument, returns downloadable JSON', 'open', 'portfolio', NULL, '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('41976b8f-5771-4671-881d-2b0373412343', 'BI-6632f03a-798a-40fc-890d-e6e66a94b1a2', 'CVE intelligence sync server action: fetchVulnerabilities(sbomComponentId) — queries OSV.dev /v1/query by purl (primary); falls back to NVD /rest/json/cves/2.0 by cpe when purl yields no results; applies CISA KEV weekly feed overlay (sets inCisaKev=true, effectiveSeverity=critical); creates/updates ComponentVulnerability records; records lastCheckedAt on SbomComponent', 'open', 'portfolio', NULL, '2026-03-21 00:34:55.555', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
