INSERT INTO public."BacklogItem" VALUES ('681393f4-39c2-4e6b-9116-ea0b22d29701', 'BI-84caa812-da0e-402d-8255-f8f5c14c8e8b', 'Update Build Studio phase prompts for autonomous operation with Dev toggle awareness', 'open', 'portfolio', 'Rewrite all 5 Build Studio phase prompts (ideate, plan, build, review, ship) in build-agent-prompts.ts for autonomous operation. Agent should produce all artifacts without asking technical questions. Plain-language user interaction. Dev toggle ON shows code/docs/plans, Dev toggle OFF hides technical details. The ideate prompt already says "Do NOT ask clarifying questions" but review/ship prompts still ask the user for decisions the agent should make itself. See EP-UX-BUILD spec Section 3 (Automated Evidence Chain).', '2026-03-21 17:51:04.704', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
