INSERT INTO public."BacklogItem" VALUES ('6c311fb3-b080-4b47-a696-af279f985522', 'BI-06bf23cb-1310-4b25-aa04-95d9b54ae525', 'Evaluate 3-way PO matching (PO → goods receipt → bill)', 'deferred', 'product', 'Trigger: customer with 10+ active suppliers and a dedicated procurement person reports that PO-to-bill conversion alone is insufficient for catching delivery shortfalls. Original decision: excluded from V1 because most SMBs under 20 employees do not use formal goods receipt workflows. When triggered: extend PurchaseOrder with GoodsReceipt model, quantity-received tracking, and three-way variance reporting before bill approval.', '2026-03-21 00:35:08.205', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('4b60bc37-5df1-4c9f-b2dd-e6c4a9274d9f', 'BI-316b1f0d-f0aa-406b-8689-6f1477babcf3', 'Evaluate customer credit limit management', 'deferred', 'product', 'Trigger: customer with 50+ accounts starts experiencing material bad debt from overextended debtors and requests credit controls. Original decision: excluded because almost no SMB sets or enforces credit limits even when the feature exists — investment went to automated reminders instead. When triggered: add creditLimit field to CustomerAccount, warn/block on new invoice creation when limit exceeded, credit review dashboard.', '2026-03-21 00:35:08.205', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('32e6d9c8-6b59-4836-b75d-c9e818d2ec15', 'BI-265b07a7-def7-4ccb-8737-b01a3f01290c', 'Evaluate subscription billing engine vs Stripe Billing integration', 'deferred', 'portfolio', 'Trigger: recurring billing (EP-FINMGMT-001 item 12) proves insufficient AND Stripe Billing integration friction is high enough that customers request native proration, plan changes, or card retry/dunning. Original decision: permanent integration boundary — Stripe/Chargebee have hundreds of engineers on this; building even 30% is a multi-year distraction. When triggered: evaluate whether the gap is integration quality (fix the connector) or genuine missing capability (spec a bounded subscription module). Default assumption: fix the integration, do not build the engine.', '2026-03-21 00:35:08.205', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('4d285a10-ed21-45ab-9a85-146ff64b5266', 'BI-362b62c2-4e2f-412f-881c-e1a4d576a08e', 'Evaluate custom financial report builder', 'deferred', 'portfolio', 'Trigger: multiple customers request report layouts not covered by the standard set AND are not sophisticated enough to use external BI tools (Metabase, Power BI). Original decision: SMBs build custom reports and never use them; businesses that need them outgrow SMB tools and move to BI platforms. When triggered: evaluate whether a lightweight saved-filter/column-picker on existing reports satisfies the need before considering a full report builder. Full report builder remains unlikely — it is building a BI tool, which is not our business.', '2026-03-21 00:35:08.205', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('2c59eaa0-a251-42e0-a483-e6e56ac9e4f8', 'BI-c68df842-4a6f-4ce1-ada5-5e11cc156507', 'CalendarEvent model (Prisma): eventType enum (platform_job|shift|time_off|appointment|holiday|meeting), startAt/endAt UTC DateTime, timezone string, allDay bool, status (draft|confirmed|tentative|cancelled), ownerUserId FK (nullable — system events have no owner), recurrenceRule (iCal RRULE string), parentEventId self-ref for recurrence expansion', 'done', 'portfolio', NULL, '2026-03-21 00:34:58.742', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
