INSERT INTO public."BacklogItem" VALUES ('15d81b6f-7b79-49c9-823f-4dbd19438e45', 'BI-06d663ba-4bd5-493d-a6d3-5daf2f835582', 'Audit all admin shell components for hardcoded color values (text-white, bg-[#xxx], etc.) and replace with theme-aware CSS variables (--dpf-text, --dpf-surface-1, --dpf-border, --dpf-muted). Every text element must use --dpf-text or --dpf-muted, never literal white/black. Covers Header, sidebar, tab navs, form inputs, cards, modals, and all admin pages.', 'open', 'portfolio', NULL, '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('ed3ea066-5ddf-4ff0-9b6b-e6e3af005ba0', 'BI-c533f76a-ca89-46d2-a132-092e071d5ff7', 'Audit storefront and portal layouts for hardcoded colors. Replace inline style objects using literal hex values with CSS variable references. Storefront layout, StorefrontNav, portal layout, sign-in forms, and all customer-facing components must respect the active branding theme in both light and dark modes.', 'open', 'portfolio', NULL, '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('af758eb8-f4d2-4e7d-b06d-3e5106b56186', 'BI-328fb770-487f-470b-92c7-87c4a84101b3', 'Add WCAG AA contrast validation to branding save flow. When a user saves brand configuration, validate that: (1) text color vs background meets 4.5:1 ratio, (2) accent color vs surface backgrounds meets 3:1 for large text and 4.5:1 for body text, (3) muted/secondary text meets 4.5:1 vs all surface backgrounds. Return warnings for near-misses (3:1–4.5:1) and block saves that produce sub-3:1 contrast on any text/background pair.', 'open', 'product', NULL, '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('2a78f363-1ce7-4150-8638-38204a60231c', 'BI-293919db-1d88-4514-9e73-5fb57563bda8', 'Extend deriveThemeTokens() to auto-correct accent colors that fail WCAG AA contrast. When a user-chosen accent would produce sub-4.5:1 contrast on light backgrounds, darken it to the nearest compliant shade while preserving hue. When it would fail on dark backgrounds, lighten it. The contrastRatio() utility already exists — wire it into the derivation pipeline. Add unit tests for edge-case accents (very light yellows, very dark blues).', 'open', 'portfolio', NULL, '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('95712d66-0a22-46cf-b804-d2611f437445', 'BI-864dba15-310f-40cc-bf67-69120216c8a3', 'Form element usability standards: all <input>, <select>, <textarea> elements must have (1) visible focus indicator with minimum 3:1 contrast against adjacent colors, (2) placeholder text meeting 4.5:1 contrast, (3) selected/active state visually distinct from default state, (4) disabled state clearly distinguishable. Create a shared CSS class or Tailwind utility layer for form elements that enforces these rules across admin, storefront, and portal.', 'open', 'portfolio', NULL, '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('848b92dd-fc45-4bae-8a00-6b92286cb2e8', 'BI-9ca34a9e-0168-4404-aa19-e97c9464359a', 'Automated visual regression tests: add Playwright or Vitest screenshot tests that render key pages (branding config, storefront homepage, portal dashboard) in both light and dark mode. Assert no text-on-background pair falls below 3:1 contrast ratio. Run as part of CI on PRs that touch CSS, theme, or branding code paths.', 'open', 'portfolio', NULL, '2026-03-21 00:52:35.7', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
