INSERT INTO public."BacklogItem" VALUES ('f97b2afa-018b-43b6-a9ab-f4d079241ec8', 'BI-REST-063', 'Add optional SMS delivery adapter for password recovery', 'open', 'portfolio', 'Extend the token-based password reset workflow with an optional SMS delivery channel behind a provider adapter. Keep email and admin-issued manual recovery as the primary MVP paths. SMS must be explicitly configured, use one-time expiring tokens, preserve neutral user messaging, and support future provider-backed delivery, audit, phone verification, consent, and rate limiting. Evaluate provider cost and compliance requirements before enabling beyond local test environments.', '2026-03-14 22:09:28.956', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
