INSERT INTO public."BacklogItem" VALUES ('4e1635ef-8852-4c57-bd55-f02113d78c9c', 'BI-LLM-006', 'Make coworker threads page-scoped by default', 'open', 'portfolio', 'Change the coworker conversation model so each route or UX surface gets its own thread by default. Keep route-aware agent selection aligned with route-scoped history, prevent prior-page context bleed, and preserve explicit future options for cross-page or portfolio-wide conversations when desired.', '2026-03-14 22:21:59.198', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
