INSERT INTO public."BacklogItem" VALUES ('f45914cc-083e-404e-b7ff-24dcfae14efa', 'BI-DEPLOY-008', 'First-time setup wizard guided by AI Coworker', 'open', 'product', 'After initial install, the AI Coworker (already running via Ollama) guides the user through first-time setup conversationally: company name, admin password, branding, portfolio preferences. Replaces a traditional form wizard with a natural conversation. The coworker explains each step and why it matters.', '2026-03-14 19:08:18.663', '2026-03-22 02:35:28.707', 8, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
