INSERT INTO public."BacklogItem" VALUES ('1190253b-46a8-4d6f-8e99-9a0a0eef5e3d', 'BI-SELFDEV-001', 'Code generation agent with sandboxed execution environment', 'open', 'product', 'Agent can generate code (components, server actions, schema changes) in a sandboxed environment. Preview changes before they affect the running platform. Requires container-based build/test isolation.', '2026-03-14 19:19:26.245', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('67d3dfd7-08df-42b0-9b52-faa8bd4f0f02', 'BI-SELFDEV-002', 'Visual feature builder for non-developers', 'open', 'product', 'Conversational interface where a business user describes what they need ("I need a customer feedback form") and the AI agent builds it. User sees a preview, approves, and it goes live. No code knowledge required.', '2026-03-14 19:19:26.25', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('c4a89aa2-657f-43b8-8963-b76400bc05b0', 'BI-SELFDEV-003', 'Governed code deployment pipeline with HITL approval', 'open', 'product', 'Code changes proposed by agents go through the same HITL governance as data changes (EP-AGENT-EXEC-001). Diff review, automated tests, human approval before merge. Audit trail for compliance.', '2026-03-14 19:19:26.254', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('529284cf-d7c0-401a-b2d0-d5cb06dc13d3', 'BI-FIN-011', 'Vendor and customer master reconciliation', 'done', 'product', 'Implement canonical matching and enrichment rules for duplicate parties, tax IDs, payment terms, and default ledgers across businesses.', '2026-03-15 05:12:02.08', '2026-03-22 02:35:28.707', 11, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('54b9f2c3-6fba-4075-ace5-8d25e1f18035', 'BI-SELFDEV-004', 'Platform self-update and version management', 'open', 'product', 'The platform can pull updates from the repository, apply migrations, install or upgrade managed runtimes, and restart itself. Every downloaded or managed runtime must register in inventory and, when employee-facing or employee-operated, create or link a DigitalProduct record in the correct for_employees portfolio context. Version rollback if something breaks. Non-technical admin can trigger updates from the platform UI. Add environment-aware placeholders for dev/test vs production footprint, resource licensing, and runtime-to-product linkage lifecycle.', '2026-03-14 19:19:26.257', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('82c18feb-476b-484c-95a8-f8ff666300d5', 'BI-SELFDEV-005', 'Automatic runtime inventory, digital product, and deployment registration', 'open', 'product', 'Ensure install, download, upgrade, and managed-runtime flows automatically register runtimes in inventory, link or create the corresponding Digital Product, and maintain instance-level deployment records per environment. Capture observed footprint, deployment endpoints, and placeholder governance state for resource usage, license review, and pre-production controls so dev sprawl is visible before production.', '2026-03-15 06:02:14.577', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('c0828870-21c6-49f3-85af-822d01154e12', 'BI-SELFDEV-007', 'Require workspace exposure metadata during runtime onboarding', 'done', 'product', 'Extend recursive build and managed runtime onboarding so every downloaded or provisioned runtime records workspace exposure, provider/consumer ownership, app launches, and governance placeholders alongside inventory and digital product registration.', '2026-03-15 16:52:49.666', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('7560db19-f678-4eba-9718-a20afb70dbe9', 'BI-SELFDEV-006', 'Development and production deployment governance placeholders', 'open', 'portfolio', 'Create factory-managed placeholder controls for newly introduced runtimes and external services across Dev and Production. Track resource footprint, licensing basis and review state, ownership, and environment-specific deployment considerations from first introduction so governance starts during development rather than after go-live.', '2026-03-15 15:45:08.019', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('b11dff72-e795-43b0-96c0-7b2a667f5c93', 'BI-WF-001', 'Unified workforce view showing humans and AI agents together', 'open', 'product', 'Transform /employee from a role registry into a workforce dashboard. Show human roles with headcount alongside AI agents with tier/capability. Each portfolio shows its combined workforce: human FTEs + agent capacity.', '2026-03-14 21:40:10.42', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
