INSERT INTO public."BacklogItem" VALUES ('3585650f-a411-4acf-870a-8ddb90bce152', 'BI-WF-003', 'RACI-A responsibility matrix per capability', 'open', 'product', 'For each CapabilityKey, show which human role is Accountable (always human, never agent), which agents Execute, which roles are Consulted and Informed. Surface in governance and employee views.', '2026-03-14 21:40:10.432', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('43f1f7bf-9d1d-43cf-bcfd-ea3427960138', 'BI-WF-004', 'Escalation chain: handoff-to-human and cross-agent referral', 'open', 'product', 'Add two new escalation outcomes to governance-resolver: escalate_to_human (agent confidence too low) and handoff_to_agent (cross-specialist referral with context transfer). New EscalationRecord model.', '2026-03-14 21:40:10.435', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('3ef1d148-f297-4bc4-ba58-e58e088db614', 'BI-WF-005', 'Agent skill profiles with SFIA 9 codes', 'open', 'product', 'Extend agent registry with AgentSkillProfile: sfiaSkillCode (e.g. ARCH, PROG, USEV), executionMode (autonomous/collaborative/advisory), maxRiskBand. SFIA 9 bridges human and agent skill taxonomies.', '2026-03-14 21:40:10.439', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('ff82524b-7927-43a2-a4c0-5afb53573169', 'BI-WF-006', 'Portfolio workforce capacity planning (human FTE + agent equivalent)', 'open', 'product', 'Add configurable fteEquivalentMultiplier per agent tier. Compute Effective Workforce Capacity per portfolio: human role headcount + (agent count * multiplier). Surface in portfolio health dashboard.', '2026-03-14 21:40:10.444', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
