INSERT INTO public."BacklogItem" VALUES ('470694d0-36cc-4651-8bcf-cbc784890845', 'BI-QUAL-001', 'Error capture API and QualityIssue model', 'open', 'product', 'New Prisma model: QualityIssue with type (runtime_error | user_report | feedback), route context, user, timestamp, error stack/description, linked digitalProductId and portfolioId (resolved via taxonomy). Lightweight POST /api/quality/report endpoint. Client-side error boundary catches unhandled exceptions and posts automatically.', '2026-03-14 21:51:35.778', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
