INSERT INTO public."BacklogItem" VALUES ('99291657-287f-4074-9dff-d4ba2bed3de9', 'BI-EMPWS-005', 'Add employee-facing request and status framework', 'in-progress', 'product', 'Provide a reusable pattern for employees to request services, submit information, track status, and see outcomes from provider teams, starting with finance and expanding to other internal functions.', '2026-03-15 16:45:11.541', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('b059b83c-85da-4e64-b466-2e8b6941b50b', 'BI-EMPWS-006', 'Map workforce roles to workspace defaults and app launches', 'in-progress', 'product', 'Use role and responsibility context to determine which workspace tiles, service cards, launch links, provider panels, and collaboration queues appear by default for each employee.', '2026-03-15 16:45:11.541', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('57baffc1-9d20-4426-bec6-920d9db9d908', 'BI-EMPWS-002', 'Build role-aware default workspace sections', 'done', 'product', 'Evolve the default workspace into sections such as My Work, My Services, Services I Provide, and My Apps. Section visibility and ordering should adapt by role and active responsibilities without creating separate workspace shells.', '2026-03-15 16:45:11.541', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('b3e2a073-f5ea-4d6e-8785-f5ade02f7378', 'BI-EMPWS-004', 'Expose provider and consumer entry points for digital products', 'done', 'product', 'Each employee-facing digital product must be able to expose both consumer and provider entry points in the workspace. Finance is the first example: finance staff use provider tools while all employees access finance services through the same workspace shell.', '2026-03-15 16:45:11.541', '2026-03-22 02:35:28.707', NULL, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8d7083h4co7lapr0ef9', 'BI-DEPLOY-001', 'Create portal Dockerfile and Docker Compose stack', 'open', 'product', 'Multi-stage Dockerfile for Next.js standalone. Compose: portal (port 3000), db (Postgres 16, volume), ollama (GPU passthrough). Auto-run Prisma migrations on startup.', '2026-03-22 02:07:45.883', '2026-03-22 20:37:36.961', 1, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8d0083g4co7al6zw241', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8d9083i4co76aiudl8e', 'BI-DEPLOY-002', 'Build Docker API client for container management', 'open', 'product', 'Server-side module talking to Docker Engine API via /var/run/docker.sock. Scoped to Ollama container: status, start/stop/restart, pull image. Auth: manage_provider_connections.', '2026-03-22 02:07:45.884', '2026-03-22 20:37:36.963', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8d0083g4co7al6zw241', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8da083j4co7yrra5wyk', 'BI-DEPLOY-003', 'Add Ollama management UI in platform', 'open', 'product', 'New section in /platform/ai: Ollama container status, start/stop/restart buttons, model list, pull new model by name, delete model, real-time pull progress.', '2026-03-22 02:07:45.886', '2026-03-22 20:37:36.964', 3, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8d0083g4co7al6zw241', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8dc083k4co7sfk2yx9a', 'BI-DEPLOY-004', 'Implement host capability detection and auto-model selection', 'open', 'product', 'Detect GPU (NVIDIA runtime), RAM. Selection: CPU <8GB -> phi3:mini, CPU 16GB+ -> llama3:8b, GPU 8GB -> llama3:8b, GPU 16GB+ -> llama3:70b-q4. Store as platform config.', '2026-03-22 02:07:45.888', '2026-03-22 20:37:36.966', 4, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8d0083g4co7al6zw241', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8de083l4co795srffz6', 'BI-DEPLOY-005', 'Auto-pull default model and auto-configure provider on first startup', 'open', 'product', 'Startup: check Ollama reachable -> check models pulled -> if none, pull auto-selected -> set Ollama provider active -> set as default for agent conversations. Zero manual config.', '2026-03-22 02:07:45.89', '2026-03-22 20:37:36.967', 5, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8d0083g4co7al6zw241', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8dg083m4co7m4mg07rt', 'BI-DEPLOY-006', 'Add health check monitoring and status indicators', 'open', 'product', 'Compose health checks on all services. Portal banner when Ollama unreachable. /api/health endpoint for external monitoring.', '2026-03-22 02:07:45.892', '2026-03-22 20:37:36.969', 6, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8d0083g4co7al6zw241', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8dp083o4co77331dl3u', 'BI-EXEC-001', 'Design AgentActionProposal schema', 'done', 'product', 'New Prisma migration. Model: proposalId (unique), threadId FK AgentThread, messageId FK AgentMessage, agentId, actionType enum, parameters Json, status (proposed|approved|rejected|executed|failed), proposedAt, decidedAt, decidedBy userId FK, executedAt, resultEntityId, resultError.', '2026-03-22 02:07:45.901', '2026-03-22 20:37:36.976', 1, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8di083n4co7hu6es2pm', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8bt08394co7t4bumlyd', 'BI-PROD-013', 'Add UX Accessibility AI Agent (AGT-903) to agent registry', 'open', 'product', 'Register a cross-cutting UX accessibility agent that reviews UI work for WCAG compliance, contrast ratios, font sizing, and dark-theme usability. Agent should be invokable during code review to flag accessibility regressions.', '2026-03-22 02:07:45.833', '2026-03-22 20:37:36.937', 5, 'cmn14a862082q4co7oh5nh8uq', NULL, 'cmn14a8at08344co7lz9f22cc', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8cq083c4co7188tp1k0', 'BI-LLM-002', 'Define agent system prompts for all 9 route agents', 'done', 'product', 'Extend RouteAgentEntry and AgentInfo types with systemPrompt field. Add prompts to ROUTE_AGENT_MAP for each of the 9 route agents describing role, capabilities, and context awareness.', '2026-03-22 02:07:45.866', '2026-03-22 20:37:36.947', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ch083a4co7vjm2iqfy', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8ct083d4co7mrvozmvy', 'BI-LLM-003', 'Add platform default provider and model selection', 'done', 'product', 'Add platform-level default provider+model config for agent conversations. Selection UI in /platform/ai with dropdown of active providers and discovered models. rankProvidersByCost (lib/ai-profiling.ts) provides auto-selection fallback.', '2026-03-22 02:07:45.869', '2026-03-22 20:37:36.949', 3, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ch083a4co7vjm2iqfy', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8cw083e4co7ms57k993', 'BI-LLM-004', 'Replace canned responses with live inference in sendMessage', 'done', 'product', 'In sendMessage server action: check for active default provider, build messages array (system prompt + last 20 thread messages + user message), call callProvider, persist response. Fall back to generateCannedResponse when no provider active. Token counts logged via TokenUsage, not stored on AgentMessage.', '2026-03-22 02:07:45.872', '2026-03-22 20:37:36.952', 4, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ch083a4co7vjm2iqfy', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8cy083f4co7u2lik70o', 'BI-LLM-005', 'Wire token usage logging into inference calls', 'done', 'product', 'Extract private logTokenUsage from lib/actions/ai-providers.ts to shared module. Call after every successful inference with agentId, providerId, contextKey=coworker, token counts, and computed cost.', '2026-03-22 02:07:45.874', '2026-03-22 20:37:36.955', 5, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ch083a4co7vjm2iqfy', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8f608484co7kwcmn3qd', 'BI-REST-014', 'Shared Zod validators in packages/validators/', 'done', 'product', 'Create packages/validators/ with Zod schemas for all API request/response shapes. Shared between REST route handlers (server-side) and api-client (client-side). Single source of truth for validation.', '2026-03-22 02:07:45.954', '2026-03-22 20:37:37.016', 14, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8e3083u4co7t1ph5k8v', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8gz084w4co7en5p0j00', 'BI-MOB-019', 'Notification history screen', 'open', 'product', 'More tab notification history showing all notifications with read/unread status. Mark as read on tap. Deep link navigation to relevant screen on notification tap. Paginated with cursor-based loading.', '2026-03-22 02:07:46.019', '2026-03-22 20:37:37.061', 9, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8gb084n4co7m6ht7r0d', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8dx083s4co7o5rs9ejt', 'BI-EXEC-005', 'Wire approval events into AuthorizationDecisionLog', 'done', 'product', 'Every proposal approval/rejection writes to AuthorizationDecisionLog: actorRef (who), actionKey (what), objectRef (entity), decision, rationale. Satisfies regulated industry audit trail requirement.', '2026-03-22 02:07:45.909', '2026-03-22 20:37:36.982', 5, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8di083n4co7hu6es2pm', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8eb083v4co7nz6nvl38', 'BI-REST-001', 'Extract shared business logic from server actions into packages/api/', 'done', 'product', 'Refactor existing server actions to separate business logic from Next.js-specific concerns. Create packages/api/ with shared functions callable from both server actions and REST route handlers.', '2026-03-22 02:07:45.923', '2026-03-22 20:37:36.992', 1, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8e3083u4co7t1ph5k8v', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8ee083w4co73i7s3xom', 'BI-REST-002', 'JWT auth middleware (issue, refresh, validate alongside NextAuth sessions, using ApiToken model for refresh tokens)', 'done', 'product', 'Implement JWT middleware that issues and validates access tokens (15-min TTL) alongside existing NextAuth sessions. Use ApiToken model for refresh tokens (30-day TTL, rotated on refresh). Dual auth: check Bearer header first, fall back to session cookie.', '2026-03-22 02:07:45.926', '2026-03-22 20:37:36.993', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8e3083u4co7t1ph5k8v', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8eh083x4co76m4vje28', 'BI-REST-003', 'Auth endpoints (login, refresh, logout, me)', 'done', 'product', 'POST /api/v1/auth/login (email+password → JWT pair), POST /api/v1/auth/refresh (rotate tokens), POST /api/v1/auth/logout (invalidate refresh token), GET /api/v1/auth/me (current user + role + capabilities).', '2026-03-22 02:07:45.929', '2026-03-22 20:37:36.995', 3, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8e3083u4co7t1ph5k8v', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
