INSERT INTO public."BacklogItem" VALUES ('cmn14a8fu084f4co7vhox9ukt', 'BI-MOB-003', 'Auth flow (login screen, JWT storage in Secure Storage, biometric unlock)', 'open', 'product', 'Login screen with email+password. Store JWT access+refresh tokens in expo-secure-store with biometric access control (requireAuthentication: true). Auto-refresh on app open. Redirect to login when refresh token expired.', '2026-03-22 02:07:45.978', '2026-03-22 20:37:37.03', 3, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8fw084g4co7yr13c7y4', 'BI-MOB-004', 'API client integration (packages/api-client/ consuming /api/v1/*)', 'open', 'product', 'Integrate the typed REST client from packages/api-client/ into the mobile app. Configure base URL, auth header injection, automatic token refresh on 401, error handling.', '2026-03-22 02:07:45.98', '2026-03-22 20:37:37.032', 4, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8fy084h4co7f6ms6eka', 'BI-MOB-005', 'Offline cache layer (SQLite for entities, MMKV for tokens/prefs)', 'open', 'product', 'expo-sqlite for relational entity caching (dashboard, epics, backlog, customers). react-native-mmkv for key-value storage (tokens, preferences, cache schema version). Repository pattern for testable storage interfaces.', '2026-03-22 02:07:45.982', '2026-03-22 20:37:37.034', 5, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8g1084i4co7hgnxfuis', 'BI-MOB-006', 'Push notification setup (expo-notifications, FCM/APNs, device registration)', 'open', 'product', 'Configure expo-notifications for both iOS (APNs) and Android (FCM). Register device token via POST /api/v1/notifications/register-device. Handle notification permissions, token refresh, and foreground/background notification display.', '2026-03-22 02:07:45.985', '2026-03-22 20:37:37.036', 6, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8g3084j4co742l2xtqb', 'BI-MOB-007', 'Deep linking (notification tap → correct screen)', 'open', 'product', 'Configure Expo Router deep linking so notification taps navigate to the correct screen using the deepLink field from Notification model. Handle cold start and warm start deep link scenarios.', '2026-03-22 02:07:45.987', '2026-03-22 20:37:37.037', 7, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8g5084k4co7f9pguemw', 'BI-MOB-008', 'Testing harness (jest-expo, RNTL, MSW, renderWithProviders, Maestro config)', 'open', 'product', 'Set up jest-expo with React Native Testing Library. Configure MSW msw/native for API mocking. Create renderWithProviders test helper with Zustand stores and navigation context. Configure Maestro for E2E flows.', '2026-03-22 02:07:45.989', '2026-03-22 20:37:37.039', 8, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8g7084l4co7246s1txy', 'BI-MOB-009', 'EAS Build + Submit configuration (eas.json, credentials, CI workflow)', 'open', 'product', 'Configure eas.json with development, preview, and production build profiles. Set up EAS credentials for iOS code signing and Android keystore. GitHub Actions workflow for CI: type check, lint, Jest tests, then trigger EAS build.', '2026-03-22 02:07:45.991', '2026-03-22 20:37:37.041', 9, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8g9084m4co72rjik1vq', 'BI-MOB-010', 'App theming (match platform brand tokens, dark mode, typography)', 'open', 'product', 'NativeWind v4 configuration matching platform brand tokens. Dark mode support matching web theme. Typography scale, spacing tokens, color palette. Minimum touch targets: 44x44pt iOS, 48x48dp Android.', '2026-03-22 02:07:45.993', '2026-03-22 20:37:37.042', 10, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8ff084c4co7fngwt40p', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8gj084o4co7wwvtdol1', 'BI-MOB-011', 'Workspace dashboard (tiles, calendar, activity feed, quick actions)', 'open', 'product', 'Home tab screen displaying health metric tiles per area, calendar widget with upcoming items, recent activity feed, and quick action buttons (create item, approve, message agent). Cached in SQLite with ''Last synced'' indicator.', '2026-03-22 02:07:46.003', '2026-03-22 20:37:37.049', 1, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8gb084n4co7m6ht7r0d', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8gl084p4co7he8g9sd0', 'BI-MOB-012', 'Epic list + detail screen', 'open', 'product', 'Ops tab epic list grouped and filterable by status/portfolio. Epic detail screen showing description, status, and linked backlog items. Pull-to-refresh with offline cache fallback.', '2026-03-22 02:07:46.005', '2026-03-22 20:37:37.051', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8gb084n4co7m6ht7r0d', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
