INSERT INTO public."BacklogItem" VALUES ('cmn14a8hn08544co7xu7xvywt', 'BI-MOB-026', 'View renderer engine (widget type → native component mapping)', 'open', 'product', 'Core rendering engine that maps DynamicView layout definitions to native widget components. Reads view schema from /api/v1/dynamic/views/:id, fetches data from dataSource endpoint, and renders widget grid.', '2026-03-22 02:07:46.043', '2026-03-22 20:37:37.075', 5, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8h5084z4co7kjfg09km', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
