INSERT INTO public."BacklogItem" VALUES ('cmn14a8hr08564co7d99px8bs', 'BI-MOB-028', 'Dynamic content caching (schema versioning, stale detection)', 'open', 'product', 'Cache form and view schemas in SQLite with version tracking. Detect stale schemas on app open by comparing cached version with server version. Drop and re-fetch when version changes. Schema version stored in MMKV as cacheSchemaVersion.', '2026-03-22 02:07:46.047', '2026-03-22 20:37:37.078', 7, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8h5084z4co7kjfg09km', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cmn14a8ht08574co7dfhb1yy4', 'BI-MOB-029', 'Dynamic content test suite (renderer tests for all field/widget types)', 'open', 'product', 'Jest + RNTL tests for form renderer (every field type renders correctly, validation fires, submit works), view renderer (every widget type renders, data binding works), and offline queue (enqueue, replay, error handling). MSW mocks for dynamic API endpoints.', '2026-03-22 02:07:46.049', '2026-03-22 20:37:37.08', 8, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8h5084z4co7kjfg09km', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
