INSERT INTO public."BacklogItem" VALUES ('cmn14a8hd08514co76glb4hb7', 'BI-MOB-023', 'Form field types (text, select, date, camera, signature, location, lookup)', 'open', 'product', 'Native component implementations for all field types: TextInput (text/textarea), BottomSheet picker (select), native date picker (date), expo-camera (camera), canvas drawing (signature), expo-location (location), searchable list (lookup), numeric input (number), Switch (checkbox/toggle), multi-select BottomSheet, radio button group.', '2026-03-22 02:07:46.033', '2026-03-22 20:37:37.071', 2, 'cmn14a862082q4co7oh5nh8uq', 'cmn14a7qj07sz4co77n7zag3h', 'cmn14a8h5084z4co7kjfg09km', NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
