INSERT INTO public."BacklogItem" VALUES ('b7df6abe-cb17-45ab-96c5-85f9857ce8ba', 'BI-a981103b-c5d9-4b65-adbc-7d3c33dbca6c', 'Audit all admin shell components for hardcoded color values (text-white, bg-[#xxx], etc.) and replace with theme-aware CSS variables (--dpf-text, --dpf-surface-1, --dpf-border, --dpf-muted). Every text element must use --dpf-text or --dpf-muted, never literal white/black. Covers Header, sidebar, tab navs, form inputs, cards, modals, and all admin pages.', 'open', 'portfolio', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('7d73dc6d-5079-442b-af84-825743df6741', 'BI-a587c3d5-05b4-41d9-a373-71593b572965', 'Fix storefront setup wizard white-on-white text — selections unreadable', 'open', 'portfolio', 'The storefront setup wizard selections screen shows white text on white background. All selection boxes are unreadable. Likely a CSS variable issue — the wizard may reference a non-existent --dpf-surface variable or have hardcoded white backgrounds that conflict with light mode text. Investigate SetupWizard.tsx and the storefront admin setup route.', '2026-03-21 17:51:04.704', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('445a40d3-997c-495f-b68d-2bbefae9c985', 'BI-7ff28c39-76b0-47c8-ae23-e26aab4821e5', 'Audit all admin shell components for hardcoded color values (text-white, bg-[#xxx], etc.) and replace with theme-aware CSS variables (--dpf-text, --dpf-surface-1, --dpf-border, --dpf-muted). Every text element must use --dpf-text or --dpf-muted, never literal white/black. Covers Header, sidebar, tab navs, form inputs, cards, modals, and all admin pages.', 'open', 'portfolio', NULL, '2026-03-21 00:35:09.734', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('48f02d01-4b64-4f15-9f51-4942b7a06ad9', 'BI-d7cd49ad-6de5-450b-8f27-df39edfecec6', 'Audit storefront and portal layouts for hardcoded colors. Replace inline style objects using literal hex values with CSS variable references. Storefront layout, StorefrontNav, portal layout, sign-in forms, and all customer-facing components must respect the active branding theme in both light and dark modes.', 'open', 'portfolio', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('dbad50b3-cb47-4d94-9c10-fc04685bcd94', 'BI-08de2819-f058-4831-b3ea-036915028ce1', 'Audit storefront and portal layouts for hardcoded colors. Replace inline style objects using literal hex values with CSS variable references. Storefront layout, StorefrontNav, portal layout, sign-in forms, and all customer-facing components must respect the active branding theme in both light and dark modes.', 'open', 'portfolio', NULL, '2026-03-21 00:35:09.734', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('cc400d47-7dcc-45eb-a6de-e85d408affd0', 'BI-4706c9d9-3199-4a8e-82e3-948164ddece6', 'Add WCAG AA contrast validation to branding save flow. When a user saves brand configuration, validate that: (1) text color vs background meets 4.5:1 ratio, (2) accent color vs surface backgrounds meets 3:1 for large text and 4.5:1 for body text, (3) muted/secondary text meets 4.5:1 vs all surface backgrounds. Return warnings for near-misses (3:1–4.5:1) and block saves that produce sub-3:1 contrast on any text/background pair.', 'open', 'product', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('afa5313e-f6d6-4a5c-890f-b10b914a5daf', 'BI-0e2a2961-efbc-46ec-94f2-2fa4e638c11c', 'Add WCAG AA contrast validation to branding save flow. When a user saves brand configuration, validate that: (1) text color vs background meets 4.5:1 ratio, (2) accent color vs surface backgrounds meets 3:1 for large text and 4.5:1 for body text, (3) muted/secondary text meets 4.5:1 vs all surface backgrounds. Return warnings for near-misses (3:1–4.5:1) and block saves that produce sub-3:1 contrast on any text/background pair.', 'open', 'product', NULL, '2026-03-21 00:35:09.734', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('812c7f99-584b-4df8-a98a-489ae4450f1f', 'BI-f731e7e0-1b05-434f-a196-f881360ec0b4', 'Extend deriveThemeTokens() to auto-correct accent colors that fail WCAG AA contrast. When a user-chosen accent would produce sub-4.5:1 contrast on light backgrounds, darken it to the nearest compliant shade while preserving hue. When it would fail on dark backgrounds, lighten it. The contrastRatio() utility already exists — wire it into the derivation pipeline. Add unit tests for edge-case accents (very light yellows, very dark blues).', 'open', 'portfolio', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('f8586179-127d-4a19-b1d2-995926601e9a', 'BI-7ebceb76-4a82-42cb-ac52-2490f1b7c21d', 'Extend deriveThemeTokens() to auto-correct accent colors that fail WCAG AA contrast. When a user-chosen accent would produce sub-4.5:1 contrast on light backgrounds, darken it to the nearest compliant shade while preserving hue. When it would fail on dark backgrounds, lighten it. The contrastRatio() utility already exists — wire it into the derivation pipeline. Add unit tests for edge-case accents (very light yellows, very dark blues).', 'open', 'portfolio', NULL, '2026-03-21 00:35:09.734', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('13105d29-f80d-4767-8c56-8d7394df469b', 'BI-adcb433a-7b67-4096-9ff9-cf72944dc0e1', 'Form element usability standards: all <input>, <select>, <textarea> elements must have (1) visible focus indicator with minimum 3:1 contrast against adjacent colors, (2) placeholder text meeting 4.5:1 contrast, (3) selected/active state visually distinct from default state, (4) disabled state clearly distinguishable. Create a shared CSS class or Tailwind utility layer for form elements that enforces these rules across admin, storefront, and portal.', 'open', 'portfolio', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
