INSERT INTO public."BacklogItem" VALUES ('279fdec1-a7fb-416d-a3cf-0def6623d407', 'BI-a20574ce-28b9-4521-82fc-e69c58823883', 'Automated visual regression tests: add Playwright or Vitest screenshot tests that render key pages (branding config, storefront homepage, portal dashboard) in both light and dark mode. Assert no text-on-background pair falls below 3:1 contrast ratio. Run as part of CI on PRs that touch CSS, theme, or branding code paths.', 'open', 'portfolio', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
