INSERT INTO public."BacklogItem" VALUES ('ad2adb2f-b5cc-4f0b-a27f-c9c23b1b215c', 'BI-ddca3e11-e5ad-4421-bb30-5238d52cfc08', 'Select/dropdown usability: <option> elements must have explicit background and text colors matching the active theme. Selected option must have a distinct visual indicator (background highlight using --dpf-accent at reduced opacity, or checkmark). Ensure cross-browser consistency on Windows, macOS, and Linux for both Chromium and Firefox.', 'open', 'product', NULL, '2026-03-21 00:35:09.734', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
