INSERT INTO public."BacklogItem" VALUES ('7c466403-85b3-408d-942f-c1f4464e9174', 'BI-70b08af4-22a6-4a76-8cef-3617b1ea6d0a', 'Document platform usability standards in /docs as a living reference. Cover: minimum contrast ratios per element type, required CSS variables for each surface/text role, form element patterns, button states, focus management, and the validation rules enforced at branding save time. This document is the source of truth for all UI development and is referenced by AI agents when generating or reviewing UI code.', 'open', 'portfolio', NULL, '2026-03-20 22:35:41.454', '2026-03-22 02:35:28.707', 8, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
