INSERT INTO public."BacklogItem" VALUES ('5d63e4fb-6283-47fc-866d-78d2f9c294ff', 'BI-0e30ecca-49fb-4823-bb73-785ffd769331', 'GDPR Regulation seed: register EU 2016/679 as Regulation entity with key obligations mapped to Articles 5-9 (lawful basis, consent), Art 13-14 (transparency), Art 15-22 (data subject rights), Art 25 (privacy by design), Art 30 (processing records), Art 32 (security), Art 33-34 (breach notification), Art 35 (DPIA), Art 44-49 (cross-border transfers). Each obligation gets default control stubs.', 'open', 'portfolio', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('c853fadc-fad8-4bec-addd-99415a090f6b', 'BI-2d65f59e-0e82-43b3-8352-346b238f9222', 'Processing Activity Register (Art 30): ProcessingActivity model — name, purpose (array of lawful bases), dataCategories (personal/special/children), dataSubjectCategories, recipients, retentionPeriod, transferCountries, technicalMeasures, organisationalMeasures. Linked to DigitalProduct and Regulation obligation. CRUD server actions + /compliance/processing-activities route.', 'open', 'portfolio', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('d4ce60db-a533-42d0-acd9-f1efdd27691a', 'BI-d95832c8-4393-483f-a952-1467feb30e9d', 'Data Protection Impact Assessment (Art 35): DpiaRecord model — processingActivityId FK, necessity (high-risk criteria checklist), risks (array of identified risks with likelihood/severity), mitigations (linked to Controls), dpoOpinion text, outcome enum (proceed/mitigate/consult_authority/abandon), consultationDate (Art 36 supervisory authority consultation if needed). CRUD + /compliance/dpia route.', 'open', 'portfolio', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('52676f23-fdcf-40d2-af5d-5821ada91db0', 'BI-5cc3b7e6-4022-4c9f-8981-2c43bdc4e2c4', 'Data Subject Request workflow (Arts 15-22): DataSubjectRequest model — requestType enum (access/rectification/erasure/restriction/portability/objection/automated_decision), subjectIdentifier (pseudonymised reference), receivedAt, dueAt (30 calendar days from receivedAt), status (received/verified/in_progress/completed/extended/refused), responseType, responseData (JSON), completedAt. Integrates with existing Incident model for escalation. CRUD + /compliance/dsr route with deadline tracking dashboard.', 'open', 'product', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('a7274f6b-5b4f-4375-b0bb-211eb32613c2', 'BI-1867c214-3a61-4ab5-9e31-d84a47858ecf', 'Breach Notification pipeline (Art 33/34): extend existing Incident model with gdprBreachFields — personalDataCategories, approximateSubjectCount, approximateRecordCount, likelyConsequences, measuresTaken, notifyAuthorityBy (72h from awareness), authorityNotifiedAt, notifySubjects bool (high risk trigger), subjectsNotifiedAt. Breach notification checklist with 72-hour countdown timer on incident detail page.', 'open', 'product', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('6de561b3-14b5-435c-8696-31ecefdd8a72', 'BI-4e7e6757-a171-4bae-978a-e4149fa7d84b', 'Consent Management: ConsentRecord model — subjectIdentifier, purpose, lawfulBasis (consent/legitimate_interest/contract/legal_obligation/vital_interest/public_task), consentGivenAt, consentWithdrawnAt, digitalProductId FK, evidenceId FK (links to Evidence for audit trail). Consent dashboard per product showing active/withdrawn counts. Withdrawal flow triggers review of processing activities.', 'open', 'product', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('471cefe3-b126-49de-b29f-f406bef1f467', 'BI-ff924d5f-be99-47db-856b-925d1e706560', 'Cross-Border Transfer Register (Chapter V): TransferRecord model — processingActivityId FK, destinationCountry, transferMechanism enum (adequacy_decision/scc/bcr/derogation/certification), legalReference, tiaCompletedAt (Transfer Impact Assessment date), supplementaryMeasures text. Dashboard showing all active transfers with mechanism validity tracking.', 'open', 'portfolio', NULL, '2026-03-21 00:35:00.38', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
