INSERT INTO public."BacklogItem" VALUES ('83484034-ae67-422e-ab7c-f627a6618da4', 'BI-CAL-002', 'Calendar pure helpers and unit tests (calendar-types.ts)', 'open', 'product', 'Create apps/web/lib/calendar-types.ts with: EVENT_TYPE_COLOURS, STATUS_LABELS, SCHEDULE_INTERVALS_MS (moved from ai-provider-types), validateCalendarInput, computeNextRunAt, formatEventTime. Port schedule helpers from ai-provider-types.ts. Write Vitest tests in calendar-types.test.ts.', '2026-03-15 22:47:41.87', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
