INSERT INTO public."BacklogItem" VALUES ('cc15e972-0404-40f0-8911-41ac101a56df', 'BI-7c468ff1-61a3-4555-8e5d-0ba0f5d795f4', 'Miro OAuth 2.0 integration: MiroConnection model — teamId, accessToken (encrypted), refreshToken (encrypted), tokenExpiresAt, connectedByUserId FK, boardPermissionScope. OAuth flow via /platform/integrations/miro with token storage in provider registry pattern. Capability-gated (manage_integrations).', 'open', 'portfolio', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 1, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('8cd3005a-5356-41bc-b71f-fb5734218b1e', 'BI-16ebe383-b5c0-4c3f-acad-98bb07b9371e', 'Board registry and mapping: MiroBoard model — boardId (Miro external ID), name, sourceType enum (value_stream/capability_map/archimate_view/freeform), sourceEntityId (FK to EA model entity), lastSyncedAt, syncDirection enum (push_only/pull_only/bidirectional), status enum (active/archived/error). CRUD server actions + /platform/integrations/miro/boards route.', 'open', 'portfolio', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('a3a8183a-4b33-4a1d-86ca-1d9c4484cd74', 'BI-f208aa28-f91c-4831-927a-90fdff5d3c24', 'EA → Miro export engine: publishToMiro(sourceType, sourceEntityId) server action — converts React Flow node/edge graph to Miro sticky notes, shapes, connectors, and frames via Miro REST API v2. Maps ArchiMate element types to Miro shape styles (color coding by layer: strategy=yellow, business=blue, application=green, technology=purple). Preserves spatial layout. Creates or updates MiroBoard record.', 'open', 'product', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('411df7d8-571e-4f88-9418-f7e6128089f9', 'BI-c3c288e7-7b64-41e6-aa84-f2e84c60610b', 'Miro → Platform sync via webhooks: register Miro webhook for board_changed events. MiroWebhookEvent model — eventType, boardId, payload (JSON), processedAt, syncResult. Webhook handler maps Miro item changes back to EA model nodes/edges — creates change proposals (not direct mutations) that surface in /ea for architect approval. Conflict detection when both sides changed.', 'open', 'product', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 4, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('f15c3598-7275-49d3-9e3d-54e5b4677655', 'BI-d16719a9-13a5-4a54-8497-e2d2c49c9659', 'Value stream map Miro template: purpose-built Miro frame layout for value stream maps — stages as horizontal swim lanes, capabilities as grouped sticky notes within stages, metrics as data tags. "Publish Value Stream to Miro" button on value stream detail page. Template includes legend frame explaining ArchiMate color coding.', 'open', 'product', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 5, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('161e97ba-fa42-4313-a9f2-36136bb054be', 'BI-e1911301-3f6f-4121-82e2-502fdfe824df', 'Capability map Miro template: hierarchical capability tree rendered as nested Miro frames with heat-map coloring (maturity level → color gradient). "Publish Capability Map to Miro" button on capability map page. Includes assessment overlay showing current vs target maturity as dual-colored badges.', 'open', 'product', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 6, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('68b1f95b-381e-4890-883e-509f65364bc3', 'BI-0a6ab87b-1e11-4d91-b4f0-caf1694fedf4', 'Collaboration session support: MiroSession model — boardId, sessionType enum (workshop/review/async_feedback), createdByUserId, participants (email array for non-platform users), startsAt, endsAt, feedbackDeadline. "Start Workshop" action creates a time-boxed Miro board with facilitator guide frame. Session summary auto-generated from Miro comments and sticky note clusters when session closes.', 'open', 'product', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 7, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('a3678b15-50dd-439c-90d3-62a43bcb5ff2', 'BI-c79d1957-11a4-4b65-912a-cfe2182fa71b', 'Miro integration dashboard: /platform/integrations/miro overview showing connected boards count, last sync timestamps, sync error alerts, pending change proposals from Miro, active collaboration sessions. Quick actions: reconnect OAuth, force-sync board, archive stale boards. Integration health shown on /platform settings page.', 'open', 'product', NULL, '2026-03-21 00:35:02.029', '2026-03-22 02:35:28.707', 8, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('7bc7e3a6-1318-4059-b515-e59938ffdd73', 'BLI-MN0TMYL1', 'Add Storefront step to onboarding tour', 'open', 'improvement', 'Storefront configuration should be part of the setup tour — where owners configure customer access to the platform. Login behavior and welcome page should adapt based on whether storefront is enabled (ties to EP-ADMIN-001 feature toggles).', '2026-03-21 21:09:43.962', '2026-03-22 02:35:28.707', 2, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public."BacklogItem" VALUES ('fd398472-407d-46e4-986b-87e96116c1c8', 'BLI-MN0THVKF', 'Move Brave Search API key config to External Services page', 'open', 'improvement', 'Brave Search API key is currently on Admin > Settings but it is functionally an external service. Should be on /platform/ai/providers alongside other external services. Same UX pattern: paste API key, test, done.', '2026-03-21 21:05:46.834', '2026-03-22 02:35:28.707', 3, NULL, NULL, NULL, NULL, 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
